export const PRODUCT = {

account_mgmt: {
  packages: ["core"],
  name: "Account Management",
  icon: "👥",
  color: "#0070D2",
  description: "Manage relationships with healthcare organizations (HCOs) and healthcare professionals (HCPs) through a comprehensive 360-degree account view. Account Management provides territory-specific account information, address tracking, affiliations mapping, ratings, and AI-powered account summarization. Sales reps can search and align accounts to territories, merge duplicates, track activity timelines, and prioritize accounts using Next Best Customer scoring. The domain supports both web and iPad offline workflows, ensuring field teams have the right account context for every interaction.",
  components: [
    {id:"account-profiles",name:"Account Profiles & Territory Info",icon:"📋",desc:"Provides a centralized dashboard view of territory-specific account data, including provider specialties, addresses, visit history, and team information. Account Territory Fields show details of Provider Account Territory Info records alongside associated visit data.",tags:["Account","ProviderAcctTerritoryInfo","ContactPointAddress","HealthcareProvider"],docs:["Account Profiles provides a centralized dashboard view of territory-specific account data for healthcare professionals (HCPs) and healthcare organizations (HCOs). The dashboard tab on the Account record page surfaces Account Territory Fields showing Provider Account Territory Info records alongside associated visit details, an Account Summary for the specific territory, and an Account Dashboard View with specialties, addresses, and a map view. Sales reps can track recent interactions and access territory-based account context without switching between multiple tabs.","The Account Address subsystem manages multiple address types including Primary Address (stored on the Contact Point Address object with an Is Primary checkbox) and Preferred Address (stored on the Provider Account Territory Info object for territory-specific communications). Custom formula fields configure how addresses are displayed across the Life Sciences Commercial app for both Contact Point Addresses and Sample Management Addresses. Field-Level Security on the Parent field of the Contact Point Address object must be granted for address management.","Activity Timeline gives a 360-degree view of all activities for an account, helping sales representatives, Key Account Managers, and Medical Science Liaisons visualize past and upcoming interactions with HCPs and HCOs. The timeline consolidates relevant account activities in one place for better collaboration, informed decision-making, and smarter pre-engagement planning. Implementing activity rollup introduces an Affiliations filter on the Activity Timeline and Calendar views to show activities from affiliated accounts."],connections:[{"planet":"engagement_planning","desc":"Account data drives activity plan target selection"},{"planet":"engagement_execution","desc":"Account context surfaces during visit planning and execution"}]},
    {id:"account-search",name:"Account Search & Alignment",icon:"🔍",desc:"Enables users to find accounts across internal Salesforce data and external systems like IQVIA OneKey or MDM via MuleSoft Direct integration. Supports advanced search by specialties, business licenses, and record types. Users can align out-of-territory accounts and prevent duplicates through Search Before Create flows.",tags:["Account","CareSpecialty","BusinessLicense","UserAdditionalInfo"],docs:["Account Search enables users to locate and manage accounts efficiently across internal Salesforce data and external systems such as IQVIA OneKey or master data management (MDM) systems via MuleSoft Direct integration. Users begin with an internal keyword search, optionally expand to external systems, and can use advanced search to refine results by attributes like specialties, business licenses, and record types. The Search Before Create flow prevents duplicate account creation by checking for existing records before initiating the creation process.","The Admin Console provides granular control over Account Search configuration at both org and profile levels, with further refinement by record type. Admins define search criteria, results layout, and the appearance and behavior of search options. The Account Search Field setting selects text fields from the Account object used for searching, while advanced search criteria enable filtering by custom attributes. Users can align out-of-territory accounts discovered through search to their assigned territories.","When users search externally, the system integrates with IQVIA OneKey via MuleSoft Direct to identify potential accounts from verified healthcare provider databases. If the required account does not exist in any system, the user confirms its absence before initiating the account creation process. This workflow maintains data integrity, reduces redundancy, and ensures that new accounts are only created when no matching record exists internally or externally."],connections:[{"planet":"common_components","desc":"Uses MuleSoft Direct for external system integration"}]},
    {id:"affiliations",name:"Affiliations & Relationships",icon:"🔗",desc:"Maps connections between HCPs and HCOs to understand the healthcare ecosystem. Affiliation records capture roles, effective dates, and relationship types. Affiliation alignment rules automatically associate accounts to territories based on account type, role, and specialty criteria.",tags:["ProviderAffiliation","HealthcareProviderSpecialty"],docs:["Affiliations maps connections between Healthcare Professionals (HCPs) and Healthcare Organizations (HCOs) to understand the healthcare ecosystem. The feature provides multiple dynamic views from the Affiliations tab on an account record page, including a Table View presenting relationships in a structured table format with effective start and end dates of Provider Affiliation records, a Hierarchy View showing Hard Affiliations in an expandable parent-child structure, and a Network View displaying connections with relationship types and roles.","Admins configure Affiliations through field sets and custom fields on the Provider Affiliation object, including Unique Field sets for deduplication, Columns field sets for table display, and Provider Affiliation Product associations. Picklist values for affiliation roles can be customized, and the display can be configured through Affiliation settings to manage data relationships and enforce data quality. Field-Level Security settings control access to affiliation data for different user profiles.","Affiliation alignment rules automatically associate affiliated accounts to specific territories based on configurable criteria including Account Type, Affiliation Role, and Specialty. After the Account to Territory, Zip to Territory, and Brick to Territory batch jobs run, the Affiliation Alignment job processes these rules automatically. Batch jobs for Affiliations efficiently handle large volumes of records by bypassing governor limits that would restrict trigger handler processing."],connections:[{"planet":"engagement_planning","desc":"Affiliation data informs engagement targeting strategies"}]},
    {id:"account-summarization",name:"Account Summarization",icon:"📝",desc:"Generates AI-powered summaries of provider accounts using Einstein Generative AI and cross-object field history tracking. Summaries include key account details and changes since the user's last interaction, available on web and offline on iPad. Supports profile-specific graph configurations for tailored summaries.",tags:["Account","ProviderAcctTerritoryInfo"],docs:["Account Summarization generates AI-powered summaries of provider accounts using Einstein Generative AI and cross-object field history tracking. The solution provides contextual information about provider accounts in a territory, including key account details and updates since the user's last interaction. Summaries are available on web and mobile devices, supporting both online and offline viewing on iPad. By default, the first-time summary shows the account's key information and all updates from the last 90 days.","The solution architecture consists of flows, invocable actions, batch jobs, prompt templates, and cross-object graphs working together. The Account object serves as the root node in the cross-object graph, referencing related objects like Healthcare Provider Specialty, Provider Visit Product Detailing, Provider Activity Goal, Inquiry, and Contact Point Address. The Summarize Provider Account Related Information prompt template generates structured JSON output with keyInfo and changeInfo sections for categorized summaries.","Profile-specific graph configurations enable separate summaries tailored to different personas such as Key Account Managers and Medical Science Liaisons. The Run Account Summarization Batch Job schedule-triggered flow runs on a daily cadence, calling the Summarize Provider Accounts batch job to generate summaries in bulk. Custom prompt templates can be created to modify summarization guidelines and categorization details, and custom batch jobs can filter accounts by type, tier, or segment for targeted summarization.","Agentforce for Account Summarization extends the capability with natural language utterances, enabling users to interact with persona-based agents in a conversational Agent window to get account summaries on the go. The solution requires the Agentforce for Life Sciences Cloud license, Einstein GPT Prompt Builder, and Einstein GPT Platform Add-on licenses. Users can access AI-generated summaries on both web and iPad platforms."],connections:[{"planet":"engagement_execution","desc":"Account summaries prepare reps for visit engagement"}]},
    {id:"ratings",name:"Ratings & Prioritization",icon:"⭐",desc:"Helps prioritize and segment customer accounts into meaningful tiers. Sales reps use ratings to focus on high-value customers, align on relevant accounts, and adjust strategies. Ratings layouts are configurable per profile and support product-level rating groupings on account record pages.",tags:["Account","LifeSciMarketableProduct","PrvdAccountUserGroupInfo"],docs:["Ratings helps prioritize and organize customer accounts into meaningful segments so sales reps can focus on the right customers, align on relevant accounts, and adjust strategies for maximum efficiency. The feature supports five rating segment types: General (Account level), Product (Provider Account Product Info), Territory (Provider Account Territory Info), Team (Provider Account User Group Info), and Address (Contact Point Address). Each segment surfaces different aspects of account prioritization.","Rating layouts are created in the Admin Console and visually represent ratings on an account's record page in both web and mobile apps. Admins add rating fields at various levels including account, territory, product, team, or address, configure display types with options like percentage change indicators, ranges, and formatting. Product ratings appear grouped under a Ratings column at the bottom, and team ratings are arranged within their own columns. The layout supports drag-and-drop positioning and resizable rating cards.","Visibility and access control enables administrators to set permissions based on user roles and profiles, sharing a single layout across multiple profiles while ensuring users see only authorized ratings. For team-based ratings with users belonging to multiple groups, the PrimaryUser field in the UserAdditionalInfo object ensures a specific group's ratings remain visible. Mobile app configuration requires object metadata cache configurations for Account, ProviderAcctTerritoryInfo, LifeSciMarketableProduct, ContactPointAddress, PrvdAccountUserGroupInfo, Group, and GroupMember objects."],connections:[{"planet":"engagement_planning","desc":"Ratings influence activity plan goal targeting"}]},
    {id:"next-best-customer",name:"Next Best Customer",icon:"🎯",desc:"Leverages user-configured data such as engagement history and territory alignment to rank accounts by priority for the next engagement. The ranked list appears on the home page with distance calculations using Google Maps geolocation data from Contact Point Address records. Quick actions let reps start visits or emails directly.",tags:["Account","ContactPointAddress"],docs:["Next Best Customer leverages user-configured data such as engagement history and territory alignment to rank accounts by priority for the next engagement. The Life Sciences Next Best Customers component displays a prioritized set of accounts on the home page, with configurable card counts between 5 and 10. Users can also filter by Next Best Customer in the Account list view and on the Calendar tab. The component replaces the older NbcTopResults component for an improved experience.","Account scoring uses Territory Account Score records with a Score Explainability Information field storing a JSON structure containing multiple scoring reasons per category, optionally including Salesforce charts for visual representation. Metrics such as HCP Interest Level, Recent Reaction, Message Priority, and Messages Sent are captured in the JSON. Quick actions allow reps to start visits or emails directly from the component, supported in the mobile app's rationale view.","Distance-based sorting calculates proximity from an account's preferred or primary Contact Point Address to the user's real-time location using Google Maps API geolocation data. Data integration rules on the Contact Point Address object determine latitude, longitude, and accuracy. The account score threshold setting defines the subset of top-scored accounts eligible for distance-based sorting, ensuring low-priority accounts do not surface just because they are nearby. Quick Account Summary can be added to the Next Best Customer card using an Actionable Relationship Center (ARC) graph with the NBC Card template."],connections:[{"planet":"engagement_execution","desc":"NBC scores drive daily visit prioritization"},{"planet":"common_components","desc":"Uses geolocation data integration rules"}]},
    {id:"territory-management",name:"Territory Management",icon:"🗺",desc:"Automates account-to-territory alignment through batch jobs that process explicit mappings, zip/postal code rules, and brick-based geographic assignments. Creates and maintains Provider Account Territory Info records with proper sharing permissions. Supports both US postal code and European brick-based territory models.",tags:["ObjectTerritory2Association","Territory2","ProviderAcctTerritoryInfo"],docs:["Territory Management automates account-to-territory alignment through dedicated batch jobs that handle large-scale data processing. Three primary batch jobs process alignments: Align Account to Territory for explicit mappings loaded from external systems, Align Zip to Territory for US postal code-based geographic assignments, and Align Brick to Territory for European brick-based geographic segments. Each job creates and maintains Provider Account Territory Info records with proper sharing permissions.","The Align Account to Territory batch job processes two primary functions: it generates or updates Provider Account Territory Info records and sharing permissions for manual territory assignments, and it removes orphaned territory assignments and sharing records for inactive accounts. A Provider Account Territory Info record without a corresponding Object Territory Association record is automatically inactivated and unshared. The Zip to Territory and Brick to Territory jobs analyze account and address data against configured geographic assignment rules.","After the account, zip, and brick alignment jobs complete, the Affiliation Alignment job runs automatically when Affiliation Rules exist in the org. This job evaluates criteria including Account Type, Affiliation Role, and Specialty to align affiliated accounts to specified territories based on Provider Affiliation records. All territory management batch jobs can be run manually on an ad hoc basis or scheduled at hourly, daily, or weekly intervals from the Admin Console, with configurable batch sizes defaulting to 200 records."],connections:[{"planet":"participant_mgmt","desc":"Territory assignments control user access to accounts"},{"planet":"engagement_planning","desc":"Territory hierarchy governs activity plan scope"}]},
    {id:"data-change-request",name:"Data Change Request",icon:"📤",desc:"Manages how data changes to accounts are submitted, validated, and implemented across web and mobile apps. Reduces manual corrections and prevents unapproved changes from being applied, ensuring data consistency and auditability across the organization.",tags:["Account"],docs:["Data Change Request (DCR) manages how data changes to accounts are submitted, validated, and implemented across the Life Sciences Cloud for Customer Engagement web and mobile apps. The feature supports ten objects: Account, HealthcareProvider, HealthcareProviderSpecialty, HealthcareProviderNPI, ContactPointAddress, ContactPointPhone, ContactPointSocial, ContactPointEmail, BusinessLicense, and ProviderAffiliation. Managed fields determine which updates trigger a Data Change Request, ensuring critical data changes are reviewed and approved through the DCR workflow.","Admins configure DCR behavior per profile with three options: Don't Apply Changes Immediately (sends DCR for approval first), Apply Changes to Each Field Individually (applies changes immediately on mobile while creating a DCR for review), and Apply Changes Immediately (applies at the field level with reversion if rejected). Each option controls the timing of when changes reflect across web and mobile apps, with mobile changes appearing on the next sync cycle after web-based decisions.","Validation types define whether data change requests undergo internal validation (managed by the organization) or external validation (managed by OneKey). For external validation via OneKey, the system enforces minimum data thresholds including mandatory primary Provider Affiliation and Healthcare Provider Specialty records for Person Accounts, and mandatory external managed fields on Account, ContactPointAddress, HealthcareProvider, and HealthcareProviderSpecialty objects. Only workplace-to-individual Hard affiliations are supported for DCR syncing with external systems."],connections:[{"planet":"common_components","desc":"DCR workflows integrate with approval processes"}]},
  ],
  dataFlow:["Admin configures territory models and account-to-territory alignment rules","Batch jobs process account alignments by zip, brick, or explicit mapping","Provider Account Territory Info records are created with sharing permissions","Sales reps search, align, and prioritize accounts using Next Best Customer scores","AI-powered account summarization provides context before each interaction"],
  connections:[{"planet":"engagement_planning","desc":"Account data drives activity plan targeting"},{"planet":"engagement_execution","desc":"Account profiles and summaries support visit planning"},{"planet":"common_components","desc":"Uses MuleSoft Direct and geolocation integrations"},{"planet":"participant_mgmt","desc":"Territory assignments control user-account access"},{"planet":"pharmacy_benefits","desc":"Payer and provider accounts support benefits processing"},{"planet":"medtech","desc":"Agreements and forecasts are tied to customer accounts"},{"planet":"agentforce","desc":"Agentforce accesses account and patient data"},{"planet":"platform_extensions","desc":"Patient cards and product catalog extend account capabilities"}]
},

engagement_planning: {
  packages: ["core"],
  name: "Engagement Planning",
  icon: "📅",
  color: "#1B96FF",
  description: "Provides strategic planning tools to align field team interactions with organizational objectives. Activity Plans translate high-level goals into specific, actionable targets for field representatives, defining cycle plans and call plans by activity type, product, and territory. The Calendar helps users visualize and optimize their schedules, while Key Account Management enables structured account plans and territory business plans with goal definitions, action plan templates, and assessment tasks. Time Off Territory management prevents scheduling conflicts by letting users log and manage time away.",
  components: [
    {id:"activity-plans",name:"Activity Plans",icon:"📊",desc:"Defines omni-channel cycle plans and call plans with specific targets by activity type (visits, meetings, emails), product, and territory. Supports weighted goal measures, goal proration based on working days, shared territory goals, and plan review workflows between reps, managers, and admins. Activity Plan Suggestions recommend accounts for inclusion.",tags:["ActivityPlan","ActivityPlanTerritory","ProviderActivityGoal"],docs:["Activity Plans translate organizational objectives into actionable cycle plans and call plans with specific targets for field representatives' interactions with healthcare professionals. Plans define targets by activity type (visits, meetings, emails), product, and territory across a set timeframe such as a quarter or fiscal year. Three plan types are supported: Account Goal (standard per-account targets), Account Goal Shared (goals shared across multiple territories on aligned accounts), and Weighted Territory Goals (priorities assigned to activity types with numerical weights from 0.01 to 9.99).","The Activity Plan workflow follows a structured lifecycle involving plan definition, review, and execution phases. During definition, admins establish goals with weighted activity types and interaction channels. The review cycle involves three stages: Employee Review (reps evaluate targets and propose modifications), Manager Review (managers validate changes within predefined tolerances), and Admin Review (final approval that activates the plan). Goal measures break down high-level goals into quantifiable targets for specific activity types measured against standard objects like Visit, Provider Visit, and Life Science Email.","Activity Plan Suggestions surface growth opportunities by recommending potential accounts for inclusion, providing field representatives flexibility to accept or decline based on territory knowledge. Goal proration automatically adjusts targets based on available working days, accounting for holidays and time off. Activity Plan Adjustments let users modify goals, add or remove accounts, and update goal measures from both web and iPad. Performance dashboards with charts show individual and team progress against goals, filterable by activity type and product."],connections:[{"planet":"account_mgmt","desc":"Activity plans target accounts based on territory alignment"},{"planet":"engagement_execution","desc":"Activity plan goals are fulfilled through visits and emails"}]},
    {id:"calendar",name:"Calendar & Scheduling",icon:"🗓",desc:"Helps sales teams visualize and prioritize visits, meetings, and time off territory events. Provides best time recommendations to avoid scheduling conflicts and create optimized daily plans. Users can save sets of visits as routines and access team members' schedules for coordinated planning.",tags:["Visit","Event"],docs:["Calendar helps sales teams visualize and prioritize key events including visits, meetings, time off territory, general events, holidays, and assessment tasks. The Calendar offers Month and Week views with configurable first day of week, work day start time, hourly slot counts, and time format settings. Each event type is color-coded with configurable hex color codes for planned, confirmed, and completed visits, time off territory, general events, holidays, and assessment tasks.","Admins configure Calendar parameters through the Admin Console Planner settings, supporting org-level defaults and profile-specific overrides. Calendar events are created using calendar metadata records that define DML classes, indicator colors, and object instances for each event type. Business hours and holiday mappings prevent scheduling conflicts by blocking visits or time off territory during designated holidays. Mirror Territory configuration enables users to view events from shared territories.","The Routine management feature allows users to save sets of visits as reusable routines, with configurable settings for sharing routines, creating multi-day routines, and error handling behavior. The My Team feature enables managers to view schedules of their team and assigned territories by assigning the relevant permission sets. Calendar requires prerequisite setup of Visit Settings (including Visit Conflict Validation Period), Lists and Filters, Account Address, and Best Time features."],connections:[{"planet":"engagement_execution","desc":"Calendar events become scheduled visits"},{"planet":"account_mgmt","desc":"Calendar shows account-specific visit history"}]},
    {id:"key-account-management",name:"Key Account Management",icon:"🔑",desc:"Drives strategic, insight-based customer engagement through structured account plans and territory business plans. Enables goal definitions with action plan templates containing trackable assessment tasks. Supports plan hierarchies with objectives, participants, and configurable action plan frameworks on both web and iPad.",tags:["AccountPlan","AccountPlanObjective","AccountPlanParticipant","GoalDefinition","GoalAssignment","AssessmentTask","ActionPlanTemplate"],docs:["Key Account Management drives strategic, insight-based customer engagement through structured Account Plans and Territory Business Plans. Account Plans are dynamic, collaborative strategies for individual customer relationships, helping dedicated account managers identify stakeholders, create plans with strategic analysis, and facilitate participant-stakeholder liaisons. Territory Business Plans promote initiatives across specific territories, enabling Medical Science Liaisons to build relationships with medical professionals and execute regional strategies.","The system uses a design-time and run-time object hierarchy. At design time, admins define Goal Definitions, Action Plan Templates with Template Versions, and Action Plan Template Items. At run time, these instantiate as Account Plan Objectives or Goal Assignments, Action Plans, and Assessment Tasks with Action Plan Items. Account Plans include additional objects for Products, Relationships, Related Object Analysis (SWOT-style factors), Stakeholders, Participants, Participant-Stakeholder junctions, Stakeholder Products, and Stakeholder Actions.","Sprints help key account managers monitor and execute assigned tasks in a timely manner. Plan progression tracking uses configurable completion statuses and trigger handlers including AccountPlanDeleteChildrenHandler, AccountPlanChangeStatusHandler, SetSprintPercentCompleteHandler, and SetAccPlanPercentCompleteHandler. Goal Definitions support global, affiliate, and territory levels with measurable targets broken down into action plan template items that represent executable assessment tasks. The framework works on both web and iPad with offline support."],connections:[{"planet":"account_mgmt","desc":"Account plans reference account data and territory info"},{"planet":"engagement_execution","desc":"Assessment tasks are completed during visit engagement"}]},
    {id:"time-off-territory",name:"Time Off Territory",icon:"🏖",desc:"Lets users log and manage time away from assigned territories with configurable rules that prevent scheduling conflicts. Admins define whether time-off entries can be created during certain event types. Predefined time slot intervals with autopopulated start and end times simplify multiday time-off creation.",tags:["TimeOff"],docs:["Time Off Territory lets users log and manage their time away from assigned territories, with configurable rules that prevent scheduling conflicts. Admins configure Time Off Territory Rules in the Planner section of the Admin Console to determine whether time-off entries can be created during certain event types. Rules can be applied at the default level for all profiles or overridden for specific profiles, with per-TOT-type parameter configurations.","Predefined time slot intervals simplify multiday time-off creation with autopopulated start and end times based on the selected slot type. The system supports All Day, Morning, Afternoon, and Evening time slots, each with configurable time intervals. When users select a slot while creating a time off territory record, the corresponding start and end times are automatically populated, reducing manual data entry and ensuring consistency.","Time Off Territory events appear on the Calendar with a dedicated color indicator (configurable hex code, default #FF5D2D) and integrate with the goal proration system in Activity Plans. Working days calculations that affect goal targets automatically account for logged time-off entries, ensuring fair and realistic targets for sales representatives. The Time Off Territory Adjustment setting in Planner enables or disables adjustments from the Calendar interface."],connections:[{"planet":"engagement_execution","desc":"Time off territory blocks prevent visit scheduling during absences"}]},
    {id:"plan-suggestions",name:"Activity Plan Suggestions",icon:"💡",desc:"Surfaces growth opportunities by recommending potential accounts for inclusion in activity plans. Provides field representatives flexibility to evaluate recommendations based on territory knowledge and accept or decline them, ensuring plans reflect both data-driven insights and field expertise.",tags:["ActivityPlan","Account"],docs:["Activity Plan Suggestions surface growth opportunities by recommending potential accounts for inclusion in activity plans. The feature provides field representatives with the flexibility to evaluate recommendations based on their territory knowledge and accept or decline them as needed, ensuring plans reflect both data-driven insights and field expertise. Suggestions appear during the activity plan creation and adjustment workflows.","Suggestions are generated based on account engagement history, ratings, product detailing goals, and territory alignment data. The system evaluates accounts that are not currently included in the activity plan but match the plan's targeting criteria such as product focus, territory scope, and activity type requirements. Recommended accounts are presented with relevant context to help representatives make informed decisions about inclusion.","The suggestion mechanism integrates with the Activity Plan Review lifecycle, allowing representatives to incorporate suggested accounts during the employee review phase before manager and admin approval. Accepted suggestions automatically create the necessary Provider Activity Goal records for the added accounts, while declined suggestions are tracked for future reference. This ensures that activity plans remain comprehensive while respecting the field team's direct knowledge of customer relationships."],connections:[{"planet":"account_mgmt","desc":"Suggestions reference account engagement history and ratings"},{"planet":"product_mgmt","desc":"Product detailing goals drive suggestion criteria"}]},
    {id:"goal-tracking",name:"Goal Tracking & Adjustments",icon:"📈",desc:"Enables users to monitor individual and team performance against activity plan goals through dashboards, charts, and contextual indicators in lists and planners. Sales representatives can adjust goals, add or remove accounts, and update goal measures. Goals prorate automatically based on available working days and holidays.",tags:["ProviderActivityGoal","ActivityPlan"],docs:["Goal Tracking enables users to monitor individual and team performance against activity plan goals through dashboards, charts, and contextual indicators in lists and planners. The Today's Pace calculation shows a representative's current progress based on either actual working days or the total time length of the activity plan. Submitted Count tracks completed and submitted activities contributing toward goal attainment, while Scheduled Count shows planned or in-progress activities not yet completed.","Sales representatives can adjust goals, add or remove accounts from plans, and update goal measures through the Activity Plan Adjustments feature. Adjustments require setup of Provider Activity Measure Type records and custom picklist values for the Adjustment Reason field on the Provider Activity Plan Adjustment object. A quick action button for Activity Plan Adjustment Request is configured through the Admin Console and added to the account record page highlights panel.","Goal proration automatically adjusts targets based on available working days, accounting for weekends, holidays, and logged Time Off Territory entries. This ensures fair and realistic targets for sales representatives. The Activity Plan By Product home page component shows each user's specific goals filtered by plan cycle type such as AccountGoal or WeightedTerritoryGoal, enabling alignment of daily work with organizational strategy. Progress visualizations appear on both home page and account profile dashboards."],connections:[{"planet":"engagement_execution","desc":"Visit and email completion updates goal progress"},{"planet":"sample_mgmt","desc":"Sample drop goals are tracked alongside visit goals"}]},
  ],
  dataFlow:["Admin creates activity plan with target channels, products, and territories","Activity plan undergoes review workflow between reps, managers, and admins","Goal measures are prorated based on working days, holidays, and time off","Account plan templates with assessment tasks are assigned to key accounts","Field reps execute against plans and track progress through dashboards"],
  connections:[{"planet":"account_mgmt","desc":"Activity plans target territory-aligned accounts"},{"planet":"engagement_execution","desc":"Plans are executed through visits, emails, and meetings"},{"planet":"product_mgmt","desc":"Product detailing goals drive visit objectives"},{"planet":"sample_mgmt","desc":"Sample distribution plans align with activity goals"}]
},

engagement_execution: {
  packages: ["core"],
  name: "Engagement Execution",
  icon: "🤝",
  color: "#3EBFE4",
  description: "Streamlines the complete visit lifecycle from scheduling through post-visit reporting. Visit Management simplifies planning, engagement, and reporting while supporting both face-to-face and remote interactions. Consent Management captures and honors HCP communication preferences across channels. Medical Inquiries provides compliant workflows for handling HCP questions including adverse events and product quality complaints. Medical Insights lets field teams capture and share structured observations from engagements. Surveys enable structured feedback collection, and Remote Engagement supports video call meetings with Twilio integration.",
  components: [
    {id:"visit-management",name:"Visit Management",icon:"📆",desc:"Optimizes the face-to-face visit lifecycle through plan, engage, and report stages. The Visit Engagement Page provides a purpose-built interface for sharing approved content, product messages, capturing samples, and recording signatures. Uses a one-to-one Visit and Provider Visit data model for extensibility.",tags:["Visit","ProviderVisit","ProviderVisitProdDetailing","ProviderVisitDtlProductMsg","ProviderVisitMarketingItem","ProviderVisitRqstSample","ProviderVisitProdDiscussion","Visitor"],docs:["Visit Management optimizes the face-to-face visit lifecycle through plan, engage, and report stages. The Visit Engagement Page provides a purpose-built interface with a configurable sidebar menu supporting up to 10 related lists including Presentation Forums, Provider Visit Product Detailings, Product Disbursements, Provider Visit Requested Samples, Provider Visit Marketing Items, Attendees, and custom objects. The system uses a one-to-one Visit and Provider Visit data model where matching record types with identical API names link the two objects for extensibility.","The sidebar Recommendations option appears as the first item when recommended messages or presentations are available for the account. Visit information configuration includes hard-coded fields (Account, Place, Planned Start Time, Planned End Time) plus configurable Channel and Status fields. Next Visit Objectives can be added to the Provider Visit page layout as either multiline text (Provider Visit Next Visit Objective) or multiselect picklist (Provider Visit Next Visit Objective Type) with Product Guidance alignment.","Visit Management supports both web and mobile workflows. Mobile app configuration requires object metadata cache configurations for Visit, Provider Visit, and related objects with metadata cache regeneration after page layout, record page, Admin Console Settings, or object configuration changes. Visit Settings in the Admin Console include Visit Conflict Validation Period in Days and Visit Conflict Validation Mode to prevent duplicate visit creation. Record type overrides use the lsc4ce:LogAVisitAction Lightning component for the New button on Visit and Provider Visit home and list view pages."],connections:[{"planet":"account_mgmt","desc":"Visits are scheduled against territory-aligned accounts"},{"planet":"intelligent_content","desc":"Presentations and messages are delivered during visits"},{"planet":"sample_mgmt","desc":"Sample drops and DTP requests occur during visits"}]},
    {id:"consent-management",name:"Consent Management",icon:"✅",desc:"Captures, synchronizes, and honors HCP communication preferences across subscription types and channels. Provides a centralized Consent tab on account pages showing opt-in/opt-out status. Supports digital signature capture, geolocation recording, and confirmation emails. Batch jobs align sharing records when territory mappings change.",tags:["CommunicationSubscriptionConsent","CommunicationSubscription"],docs:["Consent and Authorization manages the consent documents, authorization forms, and electronic signatures required for care program enrollment. The system uses Data Use Purpose records as containers for consent forms associated with each care program, supporting multiple forms per program. Authorization Form records store document metadata including revision numbers, effective dates, and signature requirements, while Authorization Form Text records manage multi-language versions of consent content.","Administrators upload consent documents to file libraries with configurable folder-level accessibility. The system supports cloning existing consent documents from one Data Use Purpose record to another, enabling efficient reuse across programs. Authorization Form Data Use junction records connect consent forms to their associated care programs, establishing the relationship between documents and program requirements.","Experience Cloud integration allows program participants to log into their site, view their care program card, and provide consent for associated documents remotely. The system supports digital signature capture, and administrators can configure whether signature is required or if the form is informational only. Multi-language support ensures consent forms display in the correct locale by matching the Authorization Form Text locale field to the site or org language."],connections:[{"planet":"intelligent_content","desc":"Email sending respects consent preferences"},{"planet":"account_mgmt","desc":"Consent status is tracked per account"}]},
    {id:"medical-inquiries",name:"Medical Inquiries",icon:"❓",desc:"Captures, manages, and responds to critical HCP questions including general medical inquiries, adverse events, and product quality complaints. Features a configurable workflow with Draft, Signed, Submitted, Assigned, and Responded stages. Sales reps create and sign inquiries while medical science liaisons assign and respond, ensuring MLR compliance.",tags:["Inquiry","InquiryQuestion","SubjectAssignment"],docs:["Medical Inquiries captures, manages, and responds to critical HCP questions including general medical inquiries, adverse events, and product quality complaints. The feature uses a configurable workflow with stages: Draft, Signed, Submitted, Assigned, and Responded, with the status tracked on the Case object. Sales representatives create and sign inquiries while medical science liaisons assign and respond, with role-specific action buttons controlled through a custom formula field that enables conditional display based on user profile.","The inquiry workflow is implemented using the LifeSciStagePathContainer Lightning component on the Inquiry record page, with configurable workflow paths based on the Inquiry object and its different stages. Each stage has defined statuses, actions, and record permissions enforced through workflow actions. The multi-object Lightning component enables users to manage both inquiry and case records simultaneously, while the Inquiry Question Answer related list uses the Related List - Life Sciences component with field sets for structured response capture.","Medical Inquiries enhances security and data integrity with a dedicated data model using the Inquiry and InquiryQuestion objects, role-based access permissions through sharing settings on the InquiryQuestion object, and mandatory signature validation rules. The MIRF Share Management batch job automates sharing and management of multiple inquiry records. Users can create inquiries from both the Inquiry record page and directly from Account record pages, with the Account page providing better context about the healthcare professional."],connections:[{"planet":"account_mgmt","desc":"Medical inquiries are linked to provider accounts"},{"planet":"common_components","desc":"Workflow paths enforce compliance stages"}]},
    {id:"medical-insights",name:"Medical Insights",icon:"💬",desc:"Provides field teams a structured way to capture and share insights from HCP and HCO engagements. Insights can be captured from Home, Account, and Visit pages with associated products, accounts, and topic tags. Supports user reactions and territory-based sharing for cross-team collaboration.",tags:["MedicalInsight","MedicalInsightAccount","MedicalInsightProduct","UserReaction"],docs:["Medical Insights provides field teams a structured way to capture and share insights from engagements with HCPs and HCOs. Insights can be captured from Home, Account, and Visit pages using quick actions, with associated products, accounts, and topic tags through the MedicalInsight, MedicalInsightAccount, MedicalInsightProduct, Subject, and SubjectAssignment objects. User reactions (UserReaction object) enable collaborative feedback on shared insights.","The system uses territory-based sharing for cross-team collaboration through the MedicalInsightSharingHandler trigger handler. Users can view insights captured by their own profile within their territories from the Medical Insights tab in the App Launcher. The record page layout includes related lists for Medical Insight Accounts, Medical Insight Products, Subject Assignments, and User Reactions, providing comprehensive context for each insight.","Configuration requires field sets linking visits to insights (VisitInsightsRLFieldSet with Name, Source Type, Content fields) and accounts to insights (AccountInsightsRLFieldSet with Name, Medical Insight, Reason Type fields). Six trigger handlers manage insight lifecycle events: PublishMedicalInsightEventHandler, RecalculateParentLinkedInsightsHandler, MedicalInsightSharingHandler, UserReactionMedicalInsightHandler, RecalculateInsightTopicNameHandler, and InsightCascadeDeleteTriggerHandler. Admin Console settings enable insight capture configuration and mandatory field requirements."],connections:[{"planet":"account_mgmt","desc":"Insights are linked to provider accounts for context"}]},
    {id:"remote-engagement",name:"Remote Engagement",icon:"📹",desc:"Facilitates virtual meetings with HCPs through Twilio video call integration. Supports meeting invitations with passcodes, participant management, screen sharing, and remote signature capture for products, samples, and consent. HCPs join through an Experience Cloud portal, and call recordings are stored for reference.",tags:["VideoCall","VideoCallParticipant","VideoCallRecording"],docs:["Remote Engagement facilitates virtual meetings with HCPs through Twilio video call integration. When users schedule remote visits, HCPs receive invitation emails with meeting links and passcodes. During meetings, users can manage participants, share screens, and capture remote signatures for direct-to-practitioner products, samples, product discussions, or consent. HCPs join through an Experience Cloud portal site, and call recordings are stored for reference in VideoCallRecording records.","Setup requires configuring Twilio as the service provider by updating named and external credentials included in the Life Sciences Customer Engagement managed package, creating an Experience Cloud site for HCP access, and adding Twilio WSS endpoints as trusted URLs. Remote Engagement channel values (such as Video Call or Remote) are added to the Visit Channel picklist field, and trigger handlers (RemoteSessionInvitationPVHandler for Provider Visit, RemoteSessionInvitationVisitHandler for Visit) generate session keys, passcodes, and send invitation emails.","Mobile app configuration requires object metadata cache configurations for VideoCall, VideoCallParticipant, VideoCallPtcpSession, and VideoCallRecording objects. The Access Remote Engagement for Digital Experience permission set provides HCPs and HCOs access to join video calls through the Digital Experience site. Actions for starting remote sessions can be configured on both account lists (via quick action) and account records (via page layout) to enable ad hoc remote session creation."],connections:[{"planet":"intelligent_content","desc":"Presentations are shared during remote sessions"},{"planet":"account_mgmt","desc":"Remote visits are logged against provider accounts"}]},
    {id:"surveys",name:"Surveys",icon:"📋",desc:"Enables design and distribution of offline mobile surveys to gather structured feedback from HCPs. The survey builder supports eight question types with territory-based and account-based sharing strategies. Survey responses sync from mobile to Salesforce objects via scheduled batch jobs, and results appear on account and account plan pages.",tags:["Survey","SurveyVersion","SurveyInvitation","SurveySubject","SurveyResponseOffline"],docs:["Surveys enable design and distribution of offline mobile surveys to gather structured feedback from healthcare professionals. The survey builder provides a drag-and-drop interface with eight question types: Date, Long Text, Multiple Selection, Picklist, Rating (Star, Static Emoji, Thumbs Up, Heart, Dynamic Emoji), Short Text (with Number or Custom validation), and Slider (with min, max, and interval). Surveys are created as Offline Mobile Survey type and can serve as templates for reuse.","Three survey sharing strategies control distribution: Account-Based Sharing (creates Survey Invitation Share records based on Account Share records), Life Sciences Marketable Product-Based Sharing (uses Product Territory Availability alignment types including Territory Subordinates, Inclusion, and Exclusion), and Territory-Based Sharing (creates shares for a territory and its subordinates). The SurveyInvitationSharingHandler trigger on the Survey Subject object automates share record creation based on the selected strategy.","Survey responses captured offline on mobile devices sync to Salesforce through a scheduled flow that triggers the Sync Survey Response Offline Records batch job, processing 50 records at a time. The Survey Engagement Context and Survey Response Offline objects use delegate-sharing governed by the LifeSciCustEngmtBase org preference. The SurveyListView Lightning component displays survey invitations on account or account plan pages, supporting retake functionality where new invitation and subject records are created for each survey attempt."],connections:[{"planet":"account_mgmt","desc":"Surveys are distributed to territory-aligned accounts"},{"planet":"intelligent_content","desc":"Surveys can be launched from the presentation player"}]},
    {id:"expense-management",name:"Expense Management",icon:"💰",desc:"Manages visit-related expense tracking and reporting with SAP Concur integration via MuleSoft Direct. Field representatives capture expenses from the mobile app with participant allocations, expense types, and compliance controls. Expense reports consolidate individual expenses for approval workflows.",tags:["Expense","ExpenseReport","ExpenseReportEntry","ExpenseType","ExpenseParticipant"],docs:["Expense Management tracks visit-related expenses and integrates with SAP Concur via MuleSoft Direct for bidirectional synchronization. The Concur Expense Sync prebuilt integration app automates the flow of expense data so field representatives can capture and manage expenses directly from the Life Sciences Cloud mobile app. This integration ensures data accuracy, policy compliance, and a unified experience across both platforms.","Field representatives capture expenses from the mobile app with participant allocations, expense types, and compliance controls using the Expense, ExpenseReport, ExpenseReportEntry, ExpenseType, and ExpenseParticipant objects. Expense reports consolidate individual expenses for approval workflows, with expense report entries tracking amounts, dates, and categorizations. The system supports read/write access for ExpenseReport and ExpenseReportEntry objects.","Mobile app configuration requires object metadata cache configurations for supported Expense Management objects to enable offline access. Before integration with SAP Concur, admins must verify that required data is available and that users have the necessary permissions. Expenses are accessible from the Visit page, linking expense tracking directly to specific provider visits and their attendees for accurate allocation and reporting."],connections:[{"planet":"account_mgmt","desc":"Expenses are allocated to visit attendees from accounts"},{"planet":"common_components","desc":"Concur Expense Sync uses MuleSoft Direct integration"}]},
  ],
  dataFlow:["Sales rep plans visit with objectives, attendees, and product details","During engagement, rep shares presentations, captures samples, and records discussions","HCP signatures are captured digitally for compliance documentation","Post-visit report records product detailings, marketing items, and expenses","Visit data updates activity plan goal progress and account timeline"],
  connections:[{"planet":"account_mgmt","desc":"Visits execute against territory-aligned accounts"},{"planet":"engagement_planning","desc":"Visit completion fulfills activity plan goals"},{"planet":"intelligent_content","desc":"Presentations and emails support visit engagement"},{"planet":"sample_mgmt","desc":"Sample distribution occurs during visit engagement"},{"planet":"common_components","desc":"MuleSoft and workflow integrations support execution"},{"planet":"medtech","desc":"Surgical visits support commercial engagement processes"},{"planet":"agentforce","desc":"Agentforce supports engagement workflows with autonomous agents"}]
},

intelligent_content: {
  packages: ["core"],
  name: "Intelligent Content",
  icon: "📚",
  color: "#4BDBF5",
  description: "Equips field teams with a comprehensive content library for delivering impactful, compliant presentations and personalized email communications. Admins upload approved presentations and manage distribution through territory alignments and activation schedules. The content library provides search, filtering, and AI-powered recommendations, while the presentation player supports interactive delivery with drawing tools, HCP feedback capture, and engagement metrics tracking. Email templates with reusable fragments enable personalized, brand-consistent communications with consent management integration and delivery analytics.",
  components: [
    {id:"content-library",name:"Content Library",icon:"📚",desc:"Provides a centralized hub for finding approved presentations through search, filtering, and topic-based navigation. Supports custom presentations assembled from existing pages, favorites, and smart content search using Data Cloud indexing. Territory-based distribution ensures users see only content approved for their region.",tags:["Presentation","PresentationPage","PresentationLinkedPage","PresentationPageProduct"],docs:["The Content Library provides a centralized hub for finding approved presentations through search, filtering, and topic-based navigation. Territory-based distribution ensures users see only content approved for their region, with presentations linked to specific products, messages, and territories. The library supports custom presentations assembled from existing pages of HTML presentations, favorites for quick access, and smart content search using Data Cloud (Data 360) indexing for concept-based search within presentation content.","Admins upload presentations and manage distribution through the Admin Console or content management REST API resources, with granular control over content visibility, activation dates, and expiration. Presentation sharing settings support Private default access with territory-based record sharing. Presentations can be sent as email attachments (requiring PDF versions) or as secure links through a Digital Experience site with configurable expiration days, ensuring HCPs always see the latest version.","Search capabilities include keyword search on configurable Presentation object fields, extended search on Presentation Page Product fields via custom formula fields, and Data 360 smart content search for concept-based discovery within presentation files. Advanced search filters help users find accounts based on presentation details. Topic assignments enable sorting and filtering presentations by theme in the content library, and collapsible content categories improve navigation for large content libraries."],connections:[{"planet":"engagement_execution","desc":"Content library is accessed during visit planning and engagement"},{"planet":"product_mgmt","desc":"Presentations are linked to specific products and messages"}]},
    {id:"presentation-player",name:"Presentation Player",icon:"🎬",desc:"Delivers tailored presentations during face-to-face and remote interactions with interactive tools including drawing, HCP feedback capture, and dynamic content. Supports mandatory pages for compliance, preview and training modes, and engagement metrics tracking via click stream entries. Works offline on iPad with full functionality.",tags:["PresentationClickStrmEntry","PresentationForum"],docs:["The Presentation Player delivers tailored presentations during face-to-face and remote interactions with interactive tools including drawing annotations, laser pointer, and dynamic content navigation. The player supports mandatory pages for compliance (ensuring field users present key messages, disclaimers, or safety information), preview and training modes that pause metric tracking, and full offline functionality on iPad. Page names can be shown instead of page numbers for improved navigation and clarity.","Engagement metrics are tracked during delivery through Presentation Click Stream Entry records, capturing pages viewed, time spent per page, navigation paths, and HCP feedback. Presenter tracking and participant tracking can be independently enabled or disabled for privacy and compliance requirements. HCP feedback is captured through thumbs up/down icons in the player menu or by tapping presentation pages, with flash indicators providing unobtrusive confirmation.","The player integrates with surveys for structured feedback collection during or after presentations, supporting survey retakes with either fresh responses or prepopulated previous answers. Geolocation tracking captures the GPS location of presentation delivery. The Lock Player on Mobile setting prevents HCPs from accessing other parts of the app while handling the device during face-to-face visits, requiring a PIN code to unlock. Player Gesture and Side settings configure menu access through swipe or tap actions."],connections:[{"planet":"engagement_execution","desc":"Presentation player is launched from within visit engagement"},{"planet":"product_mgmt","desc":"Product messages and reactions are captured during detailing"}]},
    {id:"email-templates",name:"Email Templates & Fragments",icon:"✉",desc:"Manages preapproved email templates with reusable HTML fragments that sales reps personalize for HCP communications. Templates are linked to specific products, territories, and communication subscriptions for consent compliance. Supports automated invitation emails for remote sessions and iCalendar attachments.",tags:["LifeScienceEmail"],docs:["Life Sciences email templates include reusable HTML fragments that provide a controlled framework for sales reps to send personalized, brand-consistent communications. Unlike standard Salesforce email templates, these fragments enable modular content assembly while maintaining compliance with industry standards. Templates are linked to specific products and territories through LifeSciEmailTemplate, LifeSciEmailTmplFragment, and LifeSciEmailTmplRelaFrgmt objects, with consent management integration ensuring emails respect HCP communication preferences.","Email settings are configurable at three levels: Org Default (all users), Profile (specific profiles, overrides org), and User (individual users, overrides all). General settings control subject line editing, CC recipients, and scheduled sending. Delivery settings manage HCO email capability, opt-out behavior, and third-party email service integration via the EmailQueueProcessor Apex interface. Language settings automatically filter email templates to match the account's or user's preferred language for localized communications.","Automated invitation emails support remote engagement by sending meeting details to attendees when planned visits are created. iCalendar attachments can be included with invitations. The system requires domain-level and user-level email verification for sending, with five trigger handlers managing email queue processing: EmailQueueImmediateHandler, EmailQueueRecipientHandler, EmailQueueSenderHandler, EmailAttachmentHandler, and SyncEmailResponseStatusToObjectHandler."],connections:[{"planet":"engagement_execution","desc":"Emails are sent as part of visit follow-up and outreach"},{"planet":"product_mgmt","desc":"Email templates are linked to specific product territories"}]},
    {id:"email-analytics",name:"Email Queue & Analytics",icon:"📊",desc:"Provides administrative oversight of email delivery through the email queue with status monitoring, retry management, and failure troubleshooting. Scheduled email jobs control sending cadence and track engagement metrics including open dates, bounce rates, and invitation responses. Supports third-party email service integration via Apex interface.",tags:["LifeScienceEmail"],docs:["Email Queue and Analytics provides administrative oversight of email delivery through status monitoring, retry management, and failure troubleshooting. The email queue shows recently sent emails and those awaiting delivery, giving admins visibility into the flow of communications. Scheduled email jobs control sending cadence with configurable timing and intervals for efficient large-scale HCP and HCO communications.","Engagement metrics tracked for sent emails include open dates, bounce rates, and invitation responses, feeding into reporting dashboards for campaign performance optimization. The SyncEmailResponseStatusToObjectHandler trigger synchronizes response status data back to email objects for tracking purposes. Email analytics data helps commercial teams identify which email content resonates most with HCPs and optimize future communications.","Third-party email service integration is supported through the EmailQueueProcessor Apex interface included in the Life Sciences Customer Engagement managed package. Admins create an Apex class implementing this interface and configure the Email Service setting with the class name. This enables organizations to use their preferred email delivery platform while maintaining the Life Sciences Cloud email tracking and consent management capabilities."],connections:[{"planet":"common_components","desc":"Email analytics feed into reporting dashboards"}]},
    {id:"next-best-message",name:"Next Best Message",icon:"💬",desc:"Provides tailored, dynamically generated message recommendations for each product associated with an account. Territory Account Product Message Score records store ranking data with explainability information showing metrics like HCP interest level and recent reactions. Recommendations appear in the visit engagement sidebar.",tags:["TerritoryAcctProdMsgScore","ProductGuidance"],docs:["Next Best Message provides tailored, dynamically generated message recommendations for each product associated with an account. Territory Account Product Message Score records store ranking data with Account, Product Guidance, Territory, Total Score, and Rank fields. The Score Explainability Information field contains a JSON structure with multiple scoring reasons per category including metrics like HCP Interest Level, Recent Reaction, Message Priority, and Messages Sent for transparent recommendation rationale.","Recommendations appear in the visit engagement sidebar as the first item when recommended messages or presentations are available for the account. The system can be configured using either a proprietary predictive model with data loaded into the Territory Account Product Message Score object or through manual record creation. Sharing is controlled through owner-based sharing rules for Territory Account Product Message Score using Territories as the access specification.","Content library integration shows suggested presentations based on Next Best Messages by matching presentations that share the same assigned product messages. The Show Next Best Message setting in Presentation Settings enables this cross-referencing between content library recommendations and message scoring. This creates a unified recommendation engine that guides both product discussions and content delivery during HCP engagements."],connections:[{"planet":"engagement_execution","desc":"Next best messages guide product discussions during visits"},{"planet":"product_mgmt","desc":"Messages are aligned to products and territories"}]},
    {id:"presentation-analytics",name:"Presentation Metrics & Targeting",icon:"📈",desc:"Tracks engagement data during presentation delivery including pages viewed, time spent per page, and navigation paths. Click stream entry records enable custom reports and dashboards for optimizing content strategy. Targeted presentations restrict or warn users about content relevance, while recommended presentations suggest the best content per account.",tags:["PresentationClickStrmEntry","PresentationPartyAccess"],docs:["Presentation Metrics and Targeting tracks engagement data during presentation delivery including pages viewed, time spent per page, and navigation paths through Presentation Click Stream Entry records. These records enable custom reports and dashboards for analyzing engagement patterns and optimizing content strategy. Presenter and participant metrics can be independently controlled through tracking settings for organizations with specific privacy or compliance requirements.","Targeted presentations restrict or warn users about content relevance based on account and product context. The Targeting Context setting supports two modes: Warn (shows users which presentations are targeted while providing access to others) and Restrict (shows users only targeted presentations). Recommended presentations suggest the best content per account based on Next Best Message data and product-territory alignments through the Presentation Party Access object.","Send Presentations as Links enables HCPs to review content through a Digital Experience site without downloading attachments. Rich engagement data from linked presentations includes pages viewed, time spent per page, and navigation paths. Links reflect the latest version of the presentation, expire after a configurable number of days, and are controlled by the presentation's activation and expiration dates. This capability provides actionable data for improving presentation content based on actual HCP engagement patterns."],connections:[{"planet":"engagement_execution","desc":"Presentation metrics inform future engagement strategies"}]},
  ],
  dataFlow:["Admin uploads approved presentations and email templates with territory alignments","Content is distributed to field users based on territory and product associations","Users browse the content library and receive AI-powered content recommendations","During visits, the presentation player delivers content and captures engagement metrics","Post-visit emails are sent through templates with consent verification and delivery tracking"],
  connections:[{"planet":"engagement_execution","desc":"Content is delivered during visits and remote sessions"},{"planet":"product_mgmt","desc":"Content is linked to products and product messages"},{"planet":"common_components","desc":"Data Cloud and email services support content features"},{"planet":"platform_extensions","desc":"Document automation integrates with content management"}]
},

product_mgmt: {
  packages: ["core"],
  name: "Product Management",
  icon: "💊",
  color: "#00A1DE",
  description: "Configures, classifies, and manages the pharmaceutical products that organizations discuss, market, sell, and distribute. The product hierarchy view organizes the portfolio from markets and therapeutic areas down through brands, indications, and individual sellable products (order items, promotional items, and samples). Product territory alignments control which products and messages are available in each territory for regulatory compliance. Product messages and objectives equip field users with targeted guidance including safety information, efficacy data, and dosage details for informed HCP conversations.",
  components: [
    {id:"product-hierarchy",name:"Product Hierarchy",icon:"🏢",desc:"Provides a centralized SKU-structured view of all products organized by markets, therapeutic areas, brands, indications, brand indications, and sellable products. Supports direct CRUD operations from the hierarchy view with parent-child relationships via the Life Science Marketable Product object. Product2 records represent physical sellable items.",tags:["LifeSciMarketableProduct","Product2"],docs:["Product Hierarchy provides a centralized SKU-structured view of all products organized using the Life Science Marketable Product object for all sellable and non-sellable products, and the Product2 object for physical sellable items. The hierarchy supports product types including Markets, Therapeutic Areas, Brands, Indications, Brand Indications, and Products, with parent-child relationships configured through the Parent Product field. Each product type has specific allowed child types that enforce the organizational structure.","The Product Hierarchy view emulates pharmaceutical SKU structures, enabling direct CRUD operations from the hierarchy with search, create, edit, and delete capabilities. Admins can select the product hierarchy display type to show all products at once or paginate at 500 records. Additional product information is displayed in the hierarchy using the LSCAdditionalProductDetails custom field on the Life Science Marketable Product object, which can be either a text field or formula field combining multiple values.","Business group filters provide custom views of the product tree displaying only products relevant to a user's business group. Life Science Marketable Product records of type Product must be associated with a Product2 record in the Product field to link the marketing hierarchy to physical sellable items. This overview serves all business functions including Visits, Sample Management, product detailing, and territory alignment, providing a single source of truth for the product portfolio."],connections:[{"planet":"engagement_planning","desc":"Product hierarchy drives activity plan product targeting"},{"planet":"sample_mgmt","desc":"Sample products are categorized within the product hierarchy"}]},
    {id:"product-territory-alignment",name:"Product Territory Alignment",icon:"🗺",desc:"Controls how products and product messages are assigned to territories through explicit alignment, parent-based inheritance, and explicit exclusion. Product Territory Availability records track alignment status with automatic creation of detailed availability records. Parent Territory Product Alignment extends alignments upstream in the hierarchy.",tags:["ProductTerritoryAvailability","ProductTerrDtlAvailability","LifeSciProductAcctRstrc"],docs:["Product Territory Alignment controls how products and product messages are assigned to territories through three alignment mechanisms: Explicit Alignment (direct assignment to a specific territory), Parent-Based Inheritance (automatically inherited from parent territories to child territories), and Explicit Exclusion (product unavailable in a child territory even when the parent is aligned). The final product alignment consists of only non-excluded products, whether explicitly aligned or inherited from a parent.","When products are aligned to territories, the system automatically creates Product Territory Availability records in Queued status, and an invocable action creates Product Territory Detailed Availability records for the queued records. Alignment types include Inclusion, Territory Exclusion, and Territory and Subordinates Inclusion, each with corresponding sharing rules. The Parent Territory Product Alignment admin setting enables alignments to extend upstream to all parent territories in the hierarchy.","Life Science Product Account Restriction records enable account-level product restrictions within territories. Changes to the Parent Territory Product Alignment admin setting are not applied retroactively to existing Product Territory Availability records. Trigger handlers including ProductTerrDtlAvailabilityHandler and ProductTerritoryAvailabilityExclHandler automate availability record management. Mobile app configuration requires object metadata cache configurations for Product2, Life Science Marketable Product, Product Guidance, Product Territory Availability, Product Territory Detailed Availability, and Life Science Product Account Restriction objects."],connections:[{"planet":"intelligent_content","desc":"Territory alignments control which content users can access"},{"planet":"engagement_planning","desc":"Product availability drives territory-specific activity plans"}]},
    {id:"product-messages",name:"Product Messages & Objectives",icon:"💬",desc:"Defines messages and objectives as product guidance for healthcare provider detailing. Messages include safety, efficacy, dosage, and side effect information with effective dates, priorities, and reaction tracking. Objectives represent product-related goals aligned with broader business strategies. Both are managed from the product hierarchy and aligned to territories.",tags:["ProductGuidance"],docs:["Product Messages and Objectives are implemented together as Product Guidance records, equipping field users with targeted information for healthcare provider detailing. Messages include safety, efficacy, dosage limits, success rate, and side effect information with configurable effective start and end dates, priority levels, and reaction tracking. Objectives represent product-related goals aligned with broader business strategies that users aim to achieve during customer engagement.","Messages are created from the Product Hierarchy view under individual products, with properties including name, content text description, effective dates, priority, group name and sequence for categorization, and HCP reaction capture. The Hide Reaction option allows suppressing provider reaction tracking for specific messages. Messages and objectives can be added for brands, therapeutic areas, indications, and brand-indications, and are deactivated by toggling the Active status.","Territory alignment of messages ensures field users see only messages approved for their regions, controlled through the Product Territory Alignment framework. Messages are linked to presentations and email templates for consistent content delivery, appear in the visit engagement sidebar for product discussions, and integrate with the Next Best Message scoring system. Provider Visit Detail Product Message records capture which messages were discussed and the HCP's reaction during visit engagement."],connections:[{"planet":"intelligent_content","desc":"Messages are linked to presentations and email templates"},{"planet":"engagement_execution","desc":"Product messages are discussed and recorded during visits"}]},
    {id:"product-configuration",name:"Product Configuration & Record Types",icon:"⚙",desc:"Enables creation and management of product record types aligned with product specification types for order items, promotional items, and samples. Configures the product hierarchy display type, additional detail fields, and business group filters. Product specification type mapping connects record types to the appropriate Life Sciences workflows.",tags:["Product2","LifeSciMarketableProduct"],docs:["Product Configuration enables creation and management of product record types on the Product2 object aligned with product specification types for order items, promotional items, and samples. Record types created on Product2 are mapped to product specification types through product specification record types in the Admin Console, connecting each record type to the appropriate Life Sciences workflow. This mapping ensures that products flow correctly through inventory, sampling, ordering, and promotional processes.","The Admin Console Product Configuration page provides centralized access to creating product record types, mapping specification record types, selecting hierarchy display types, and configuring additional product detail fields. The product specification type mapping uses the Product Specification Record Type object to align each Product2 record type (such as Orders, Promotional Items, or Sample Products) with the corresponding specification type and feature area designation.","Product record types cascade through the system, affecting how products appear in Visit Management sidebar menus, Sample Management inventory operations, and product detailing workflows. The LifeSciMarketableProductMetadataHandler trigger handler manages metadata synchronization, while the ProductGuidanceDeactivationHandler controls the lifecycle of associated product guidance records when products are modified or deactivated."],connections:[{"planet":"sample_mgmt","desc":"Sample product record types drive inventory management"}]},
    {id:"product-priority",name:"Product Priority & Organization",icon:"📋",desc:"Helps users prepare for product detailing by sorting products aligned to a territory by relative importance. Priority ordering ensures field teams discuss the most important products first during HCP interactions, aligning daily activities with organizational commercial strategies.",tags:["ProductTerritoryAvailability"],docs:["Product Priority helps users prepare for product detailing by sorting products aligned to a territory by relative importance. The priority ordering ensures field teams discuss the most important products first during HCP interactions, aligning daily activities with organizational commercial strategies. Products assigned to the same territory are organized by their priority ranking to guide the sequence of detailing conversations.","The Organize Products Aligned to a Territory by Priority feature is configured through the Admin Console under Product settings. Priority values are stored on the Product Territory Availability object, linking each product's importance ranking to its specific territory assignment. This ensures that different territories can prioritize the same products differently based on regional commercial strategies and market conditions.","Product priority integrates with the visit engagement workflow where the sidebar menu and product detailing sections present products in priority order. It also influences content and message recommendations through the Next Best Message system, where product priority contributes to scoring calculations alongside HCP interest level and recent reactions. This creates a consistent prioritization experience from planning through execution of HCP engagements."],connections:[{"planet":"engagement_execution","desc":"Product priority guides detailing order during visits"},{"planet":"intelligent_content","desc":"Priority influences content and message recommendations"}]},
  ],
  dataFlow:["Admin creates product hierarchy with markets, brands, indications, and sellable products","Product record types are mapped to specification types for workflow alignment","Products and messages are aligned to territories with inheritance and exclusion rules","Product Territory Availability records control field user access per territory","Field reps access products, messages, and objectives during visit engagement"],
  connections:[{"planet":"engagement_planning","desc":"Products define activity plan detailing goals"},{"planet":"intelligent_content","desc":"Products are linked to presentations and email templates"},{"planet":"sample_mgmt","desc":"Sample products are managed within the product hierarchy"},{"planet":"medtech","desc":"Medical device products feed into sales agreements and inventory"}]
},

sample_mgmt: {
  packages: ["core"],
  name: "Sample Management",
  icon: "💊",
  color: "#0051BA",
  description: "Enables pharmaceutical companies to efficiently handle and distribute drug samples to healthcare providers. Sample Management tracks sales representative inventories, enforces regulatory compliance through sample limits and territory quantity allocations, and maintains accurate records of distribution. The system covers the complete sample lifecycle from inventory receipt and storage through disbursement during provider visits, with built-in controls for production batch tracking, inventory count assessments, and automated limit enforcement to support ethical practices and regulatory compliance.",
  components: [
    {id:"sample-inventory",name:"Sample Inventory Management",icon:"📦",desc:"Centralized dashboard for managing sample inventory operations including transfers, returns, counts, and disbursements. Sales reps can request and manage samples, track product batch items, and acknowledge received inventory all from a single interface.",tags:["ProductItem","ProductBatchItem","InventoryOperation","ProductDisbursement"],docs:["Sample Inventory Management provides a centralized dashboard for managing all sample inventory operations within Life Sciences Cloud. Sales representatives can request and manage samples, track product batch items, acknowledge received inventory, and perform disbursements from a single interface. The dashboard consolidates inventory operations, counts, transfers, returns, and disbursement processes, giving users a unified view of their sample inventory status across all assigned locations and products.","The system uses a layered data model linking Products, Life Science Marketable Products, Production Batches, Product Items, Product Batch Items, Locations, and Users. Each sales rep is assigned a Location record representing their inventory on hand, and Product Batch Items establish the relationship between products and the rep's allotted quantities organized by production batch. The allotted quantity is automatically updated whenever the rep executes an inventory operation such as a transfer, return, or disbursement.","Administrators configure org-wide and profile-level settings through the Admin Console, including inventory operation statuses, product request approval thresholds, and validation types for unsynced records. The dashboard supports custom field sets to control which columns appear in inventory count assessments, inventory operations, and disbursement processes. Quick action buttons enable resolving unresolved disbursements that occur when reps disburse samples before acknowledging received inventory.","Sample Inventory Management works both online and offline in the Life Sciences Cloud mobile app through object metadata cache configurations. Over 15 trigger handlers automate business logic including transfer locks, product batch item ownership, inventory operation synchronization, and disbursement inventory creation. The system integrates with Visit Management for sample drops during provider visits and with Product Management for marketable product records."],connections:[{"planet":"engagement_execution","desc":"Samples are disbursed during provider visits"},{"planet":"product_mgmt","desc":"Sample products reference marketable product records"}]},
    {id:"sample-limits",name:"Sample Limits",icon:"🛑",desc:"Enforces regulatory compliance by controlling how many samples can be distributed per account, visit, and time period. Uses configurable templates with country-specific and custom rules to prevent oversampling and reduce audit risks.",tags:["ProviderSampleLimit","SampleLimitTemplate","PrvdVstSmplLmtTransaction"],docs:["Sample Limits enforces regulatory compliance by providing precise control over how many samples can be distributed per account, visit, and time period. The system uses configurable sample limit templates containing rules, operations, and limits that are assigned to products or product groups. Each time a sales rep disburses a sample during a visit, a Provider Visit Sample Limit Transaction record is created and the related Provider Sample Limit records are updated automatically, with errors or warnings preventing reps from exceeding defined limits.","Life Sciences Cloud includes several types of sample limit templates: default country-specific templates for Belgium, Germany (AMG and AMG+EPFIA), Italy (Class A and C), Netherlands, and Turkey; a default generic template with customizable rules; custom cloned generic templates supporting multiple template priorities and warning or error enforcement; and advanced templates for complex regulatory requirements such as rolling start, fixed start, date range, and calendar year period types with up to three rules per template.","Administrators manage sample limits through a complete lifecycle: creating templates, assigning them to products via the Template Product Assignments page, initializing limits for individual accounts or account segments using batch jobs, and automating limit initialization for newly created HCP and HCO accounts through trigger handlers. Account segments can be created using Actionable Lists powered by the Data Processing Engine to customize distribution strategies for different account groups.","Sample limit trigger handlers including CalculateShippedQuantityHandler, SampleLimitTransactionHandler, NewAccountSampleLimitInitHandler, and NewAccountSampleLimitInitHandlerforHCO automate large-scale record processing. Failed batch jobs can be reprocessed through Apex code in the Developer Console. The system supports deleting and replacing sample limits when templates or requirements change, ensuring ongoing regulatory compliance."],connections:[{"planet":"engagement_execution","desc":"Limits are validated during visit submission"},{"planet":"common_components","desc":"License validation checks required for controlled substances"}]},
    {id:"territory-allocations",name:"Territory Product Quantity Allocations",icon:"📊",desc:"Controls which products are available in each sales territory and in what quantities. Allocations define how many samples a territory can distribute during a specified period, supporting strategic distribution planning and inventory budgeting.",tags:["TerritoryProductQuantityAllocation"],docs:["Territory Product Quantity Allocations control which sample products are available in each sales territory and in what quantities as part of a company's strategic distribution planning. Administrators assign sample quantities to territories for specified periods, and sales reps can only distribute or request approved samples that are allocated to their assigned territories. This feature manages inventory budgeting and ensures strategic sample distribution at the territory level.","While sample limits operate at the account level to enforce regulatory compliance per HCP, territory product quantity allocations operate at the territory level to control overall inventory management and budgeting. Organizations can use both features together to control the total quantity of samples allocated to territories while also limiting how many samples individual reps can distribute per account and visit within that territory and period.","Creating a territory product quantity allocation record involves selecting the product and territory, defining an enforcement period, choosing an allocation type (Drop for in-person visits or Ship for direct shipping), and setting quantities including Allocated Quantity, Adjustment Quantity, Ordered Quantity, and Max Disbursement Limit Quantity. After a visit is submitted or signed, the allocation records are automatically updated with debited and remaining quantities reflecting the disbursement.","Administrators can enforce validations when users submit visits by enabling the Validate Territory Quantity Inventory setting in Visit Administration. This setting can be configured to either show an error and prevent submission or show a warning while allowing the visit to proceed, providing flexibility in how strictly territory allocations are enforced during field operations."],connections:[{"planet":"engagement_planning","desc":"Territory allocations align with engagement planning targets"}]},
    {id:"production-batches",name:"Production Batch Tracking",icon:"🏷",desc:"Organizes sample products into trackable batches with unique identification numbers and expiry dates. Products are tracked by batch across all inventory operations, counts, acknowledgments, returns, and disbursements for full traceability.",tags:["ProductionBatch","ProductBatchItem"],docs:["Production Batch Tracking organizes sample products into trackable batches with unique identification numbers and expiry dates for full pharmaceutical traceability. Each production batch is linked to a Product record and contains a system-generated Production Batch Name along with an optional Unique Identification Number for external tracking. Products are tracked by batch across all inventory operations including counts, acknowledgments, returns, and disbursements.","The batch tracking system supports the complete sample inventory lifecycle. When administrators create production batches, they specify the product, activation status, unique identification number, quantity unit of measure, and expiry date. Product Batch Items then establish the relationship between the production batch, product, location, and user, capturing information about the products allocated to each sales rep organized by their respective batches.","Production batch tracking is essential for regulatory compliance in the pharmaceutical industry. If the Unique Identification Number is populated, Sample Inventory Management tracks batches using that external identifier; otherwise, the system falls back to the system-generated Production Batch Name. The Active Batch Assignments setting controls whether only active batch assignments are considered for inventory processes such as counts, transfers, returns, and disbursements.","Batch tracking integrates tightly with the sample disbursement process during provider visits, ensuring that every sample distributed to a healthcare provider can be traced back to its specific production batch. This traceability supports audit requirements and enables organizations to quickly identify and manage any batch-related issues such as recalls or quality concerns."],connections:[{"planet":"product_mgmt","desc":"Production batches link to product records"}]},
    {id:"inventory-counts",name:"Inventory Count Assessments",icon:"📋",desc:"Supports ad hoc, periodic, initial, and audited inventory counts. Assessors verify physical inventory against system records, resolve discrepancies through manual adjustments, and auditors can request and perform independent verification of counts.",tags:["InventoryCountAssessment","InventoryCntProdtBatchItem"],docs:["Inventory Count Assessments enable organizations to verify physical sample inventory against system records through four types of counts: ad hoc, periodic, initial, and audited. Sales representatives perform counts to reconcile their physical stock with the quantities recorded in the system, while auditors can request and perform independent verification of counts. The system prevents duplicate initial-type inventory count assessments and locks records when they reach specified statuses.","Administrators configure inventory count assessment settings at the org or profile level through the Admin Console. Configurable options include which columns to display (such as Quantity Received, Quantity Released, Total System Count, and Opening Count), whether to hide inventory operations history during count assessments, and whether to show only records assigned to the current user. The fields displayed in each count type are controlled through field sets on the Inventory Count Assessment object.","When discrepancies are found between physical inventory and system records, users can manually adjust the counts. The system tracks all adjustments through inventory operations with full audit trails. The InventoryCountAssessmentLockHandler and InventoryCountPBILockHandler trigger handlers prevent modifications to locked records, while the InventoryCntPBIValidationHandler prevents updates when unresolved product disbursement records exist for the same product.","Inventory count data feeds into reports and dashboards for compliance monitoring and operational visibility. The count assessment process integrates with the broader sample inventory management workflow, supporting the organization's regulatory obligations to maintain accurate records of all pharmaceutical sample distributions and holdings."],connections:[{"planet":"common_components","desc":"Inventory data feeds into reports and dashboards"}]},
    {id:"inventory-operations",name:"Inventory Operations",icon:"🔄",desc:"Manages transfers, returns, adjustments, and disbursements of sample inventory. Supports transferring samples between users and locations, returning samples to the warehouse, and tracking all movements with full audit trails.",tags:["InventoryOperation","ProductTransfer","ProductRequest","ProductRequestLineItem"],docs:["Inventory Operations manages the complete lifecycle of sample inventory movements including transfers between users and locations, returns to the warehouse, manual adjustments, and disbursements during provider visits. Each operation type has configurable statuses and lock states that control when records can be modified, ensuring data integrity throughout the inventory management process.","The system supports multiple operation workflows: Transfer Out operations move samples from one user's inventory to another or to a different location; Transfer In operations receive samples from transfers and shipments, requiring acknowledgment; Return operations send samples back to the warehouse; and Adjustment operations resolve inventory count discrepancies. Each operation creates detailed records with full audit trails tracking every movement of sample inventory.","Disbursement operations are created automatically when visits are submitted, linking the sample distribution to the specific provider visit record. The system handles unresolved disbursements that occur when a user distributes samples before acknowledging received inventory. In these cases, a Product Disbursement record is created with a warning, and the system temporarily pauses updates to the Product Batch Item's Remaining Quantity and Product Item's Quantity On Hand fields until the user resolves the disbursement.","Multiple trigger handlers govern inventory operations: InventoryOperationLockHandler prevents modifications to locked records, InventoryOperationSyncTxnHandler prevents creation of operations when records are in final state and checks for pending sync transactions, ProductTransferLockHandler and ProductTransferValidationHandler manage transfer validations, and TransferOutTriggerHandler handles transfer out logic. Custom action buttons on Inventory Count Assessment and Inventory Operations records can be overridden with Lightning components for specialized workflows."],connections:[{"planet":"engagement_execution","desc":"Disbursement operations are created from visit submissions"}]},
  ],
  dataFlow:["Admin creates products, production batches, and allocates quantities to territories","Sales rep receives inventory and acknowledges product batch items at their location","During provider visits, rep selects samples to disburse with limit validation","System creates disbursement records and updates inventory counts and remaining quantities","Periodic inventory count assessments verify physical stock against system records","Returns and transfers move inventory between reps, locations, and the warehouse"],
  connections:[{"planet":"product_mgmt","desc":"Sample products managed as marketable products"},{"planet":"engagement_planning","desc":"Territory allocations guide sampling strategy"},{"planet":"engagement_execution","desc":"Samples disbursed during provider visits"},{"planet":"common_components","desc":"License validation and reporting for sample compliance"},{"planet":"medtech","desc":"Field inventory management intersects with sample tracking"}]
},

common_components: {
  packages: ["core"],
  name: "Common Components",
  icon: "🧩",
  color: "#4B5563",
  description: "Shared platform capabilities that support all Life Sciences Cloud for Customer Engagement features. Common Components includes App Alerts for in-app notifications, license management for healthcare provider compliance validation, multi-object components for consolidated data views, dynamic tree views for hierarchical data exploration, provider bulk sync for IQVIA OneKey integration, configurable workflows for guided business processes, and Data 360 integration for unified data harmonization. These cross-cutting components provide the foundational infrastructure that powers field sales operations across the platform.",
  components: [
    {id:"app-alerts",name:"App Alerts",icon:"🔔",desc:"Delivers in-app notifications, recommendations, and guided actions to sales reps across web and mobile. Alerts can be targeted to specific territories, triggered automatically by Business Rules Engine, or surfaced from external systems with deep-link support.",tags:["AppAlert","AppAlertTerritory","AppAlertUserResponse","RecordAlert"],docs:["App Alerts delivers in-app notifications, recommendations, and guided actions to sales representatives across web and mobile platforms within Life Sciences Cloud. Alerts can be created manually as records, triggered automatically through the Business Rules Engine or Salesforce Flows based on real-time conditions, or surfaced from external systems. Each alert is targeted to specific territories through App Alert Territory junction records, ensuring only users assigned to those territories see the notifications during the specified time period.","The system supports three alert types: Notifications, Recommendations, and Guided Actions, plus an Announcement type for home office communications. On mobile, alerts appear through a bell icon in the app header with a message pane organized by type, supporting dismiss, resolve, deep-link navigation, and external app linking. On web, alerts appear in the Notifications List Lightning web component with support for marking alerts as read. Guided actions remain active until dismissed or resolved, while other alerts follow configurable visibility rules based on ValidUntilDate.","The Additional Message field on the App Alert object enables rich alert customization through a JSON structure supporting HTML formatting, deep links to Salesforce tabs and records, external website links, quick actions, third-party app deep linking (such as Slack), categorized tags for visual context, and action buttons with required or optional dismissal reasons. User responses are tracked through the App Alert User Response object for analytics and compliance purposes.","App Alerts requires activation of specific trigger handlers and configuration of object metadata cache for offline mobile access. The system supports both standard App Alert records for broad notifications and Record Alert records for targeting specific records such as Accounts and Healthcare Providers. Alerts can include custom HTML formatting for announcements, trusted image URLs, and support for multiple territory associations per alert."],connections:[{"planet":"engagement_execution","desc":"Alerts notify reps about account and visit updates"},{"planet":"account_mgmt","desc":"Record alerts target specific account records"}]},
    {id:"license-management",name:"License Management",icon:"📜",desc:"Validates healthcare provider licenses before sample distribution to ensure regulatory compliance. Supports state license numbers, state distributor licenses, and DEA numbers with configurable custom formula-based validity checks and visual indicators across visits, searches, and record pages.",tags:["BusinessLicense"],docs:["License Management in Life Sciences Cloud validates healthcare provider licenses before sample distribution to ensure regulatory compliance with legal and pharmaceutical standards. The system evaluates three types of licenses: State License Numbers (SLNs) verifying that HCPs are authorized to practice medicine within a specific US state, State Distributor Licenses (SDLs) for entities distributing dangerous drugs in states requiring specific licenses such as Terminal Distributor of Dangerous Drugs in Ohio, and Drug Enforcement Administration (DEA) numbers for providers who prescribe controlled substances.","Administrators configure custom formula-based validity checks on the Business License object using checkbox return types that serve as automated indicators of license validity. These formulas can incorporate any Business License fields to create flexible validation logic tailored to the organization's compliance requirements. The standard license validity formulas provided by Life Sciences Cloud can be extended or replaced with custom formulas to meet specific regulatory needs.","License validity indicators can be configured to appear in multiple contexts including during visits, in account and provider searches, in list views, and on Lightning record pages. Each license type (SLN, SDL, DEA) has its own setup section in the Admin Console where administrators can choose whether settings apply org-wide or to specific profiles, select the validation formula, and control where validity icons are displayed. For SDL validations, specific states requiring the license can be selected.","The license management process integrates directly with sample disbursement workflows. During visits, sales reps can verify whether the healthcare provider receiving the sample holds valid licenses, and the system can block or warn about distributions to providers with invalid or expired licenses. This integration ensures that organizations maintain audit-ready compliance records for all sample distributions involving controlled or regulated substances."],connections:[{"planet":"sample_mgmt","desc":"License validation enforced during sample disbursement"},{"planet":"account_mgmt","desc":"License status displayed on provider account records"}]},
    {id:"multi-object-components",name:"Multi-Object Components",icon:"🗂",desc:"Consolidates fields from several related objects onto a single record page for streamlined data entry and viewing. Supports multi-object create, edit, and view operations for accounts, inquiries, visits, and provider visit objects to reduce page navigation.",tags:["Account","Visit","ProviderVisit"],docs:["Multi-Object Components in Life Sciences Cloud consolidate fields from several related objects onto a single record page, simplifying data entry and viewing for accounts, inquiries, visits, and provider visit records. The managed package includes three Lightning components: MultiEntityCreateOverride for creating multiple records at once, MultiEntityEditOverride for updating fields across related records simultaneously, and Multi-Object Record View for displaying details from related objects on a single page.","The components support specific object combinations: Account objects show fields from the Healthcare Provider object; Inquiry objects include fields from the Case object; and Visit objects display fields from the Provider Visit object and vice versa. The components work by overriding standard New and Edit buttons on supported objects with the Life Sciences Lightning components, enabling users to populate and manage fields across object boundaries without navigating between multiple pages.","Multi-object components support multiple object types, picklist assignments, and picklist field dependencies. When users create records through these components, if one record encounters an error, no new records are created, maintaining data consistency. Validation rules and errors appear at the top of the page rather than inline, and the details shown in each component depend on existing parent and related records.","These components are automatically included in default Lightning record pages when the Life Sciences Customer Engagement managed package is installed. They function consistently across desktop and the Life Sciences Cloud mobile app because overrides applied in Lightning Experience also apply to mobile. The Search Before Create component is used specifically for the New button override on Account objects to prevent duplicate account creation."],connections:[{"planet":"engagement_execution","desc":"Multi-object views simplify visit record management"}]},
    {id:"dynamic-tree-view",name:"Dynamic Tree View",icon:"🌳",desc:"Configurable hierarchical component that displays related data in an expandable tree structure. Shows account hierarchies, territory-provider alignments, and other parent-child relationships with search, filtering, and progress bar visualization capabilities.",tags:["DynamicTreeViewConfig","DynamicTreeViewObjectConfig"],docs:["Dynamic Tree View is a configurable hierarchical component that displays related Life Sciences Cloud data in an expandable tree structure. Users can explore related records in one place without navigating to multiple pages, making it ideal for visualizing account hierarchies within health systems, territory-provider alignments, and other parent-child-grandchild relationships. The component supports search, filtering, custom sort orders, and progress bar visualization for percentage fields.","Configuration involves two steps: creating object configurations and then creating component configurations. Object configurations define the data shown for each level in the hierarchy, including the object API name, field sets for columns and info icons, parent object lookup fields, custom filter logic (such as Status = 'Active'), and sort order preferences. Component configurations then reference these object configurations to establish the parent, child, and optional grandchild relationships, including support for junction objects between levels.","Administrators create Dynamic Tree View configurations through the Component Library in the Admin Console. Each object configuration specifies field sets that control which fields appear as columns in the tree and which fields appear in the info icon popover. The component configuration supports optional search bars, record filtering, and junction object relationships with configurable lookup fields for both the grandparent and related objects.","Once configured, the component is added to a parent object's Lightning record page through Lightning App Builder by entering the API name of the Dynamic Tree View Component Configuration. Visibility rules can be applied based on record fields, device types, or other filters. The component adapts dynamically based on the configuration, making it reusable across different record pages and object hierarchies throughout the Life Sciences Cloud application."],connections:[{"planet":"account_mgmt","desc":"Visualizes account hierarchies and provider relationships"}]},
    {id:"provider-bulk-sync",name:"Provider Bulk Sync",icon:"🔄",desc:"Integrates HCP and HCO data from IQVIA OneKey directly into the Life Sciences Cloud data model via MuleSoft Direct. Provides verified healthcare provider data for territory planning, engagement activities, and address synchronization with automated batch processing.",tags:["ProviderAffiliation","ContactPointAddress"],docs:["Provider Bulk Sync enables life sciences organizations to integrate Healthcare Provider (HCP) and Healthcare Organization (HCO) data from IQVIA OneKey directly into the Life Sciences Cloud data model via MuleSoft Direct integration. This automated batch processing capability ensures organizations have access to verified provider data for territory planning, engagement activities, and address synchronization, reducing manual data entry and improving data accuracy across the platform.","The sync process populates key Salesforce objects including Account, Healthcare Provider, Provider Affiliation, and Contact Point Address records with verified data from IQVIA OneKey. This integration provides sales teams with accurate and up-to-date information about healthcare providers and organizations, including their specialties, affiliations, addresses, and practice details, which is essential for effective field engagement and regulatory compliance.","Provider Bulk Sync supports the Account Search and Alignment feature by ensuring that external provider data is available alongside internal Salesforce data when users search for accounts. The synced data enhances territory management by providing reliable provider information for account-to-territory alignment rules, and it supports the Consent Management feature by maintaining accurate contact information for communication preference tracking.","The integration leverages MuleSoft Direct to handle the complexity of mapping external data formats to the Life Sciences Cloud data model, including handling duplicate detection, record matching, and field-level updates. Organizations can configure the sync frequency and scope to balance data freshness with system performance, ensuring their provider database stays current without overwhelming system resources."],connections:[{"planet":"account_mgmt","desc":"Synced provider data populates account records"},{"planet":"intelligent_content","desc":"Provider data enhances content targeting"}]},
    {id:"workflows",name:"Workflows for Life Sciences",icon:"⚙",desc:"Configurable multi-step workflows that automate business processes and guide users through tasks with role-based permissions, stage-specific actions, and custom validation scripts. Supported online and offline in the Life Sciences Cloud mobile app for field operations.",tags:["LifeSciStageAction","LifeSciStageObject","LifeSciCustomScript"],docs:["Workflows for Life Sciences Cloud automate business processes and guide users through multi-step tasks with configurable permissions, actions, and validation rules at each step. A workflow path outlines an object's journey through various stages controlled by a picklist field, with each stage supporting multiple stage operations that define the conditions, permissions, and actions available to users. These workflows are supported both online and offline in the Life Sciences Cloud mobile app.","Each workflow is built around several key constructs: workflow actions define the operations users can perform (updating records, launching platform events, invoking Lightning web components, or opening custom URLs); stage objects represent the objects with configured workflow paths; stage operations group conditions that records must meet; and stage operation actions assign specific actions to each workflow stage. This layered architecture enables fine-grained control over what users can do at each step of a business process.","Custom scripts serve as programmatic validation and guidance tools within workflows. Validation scripts run each time a user performs an action, preventing incorrect operations or alerting users about errors. Checklist scripts display an info icon on Update Record actions showing users the tasks they need to complete before moving to the next stage. Custom scripts use global variables for accessing environment details, database interactions, current record data, and user information.","Workflow configuration is managed through the Workflow Configuration tile in the Admin Console, where administrators can create, clone, search, and manage workflow paths. The StagePathPermissionsHandler trigger handler must be activated for workflows to function. Sharing settings for Life Science Custom Script, Stage Action, and Stage Object must be set to Public Read Only. Workflow configurations can be moved between orgs using Data Loader for deployment management."],connections:[{"planet":"engagement_execution","desc":"Workflows guide visit and inquiry processes"}]},
    {id:"data-360-integration",name:"Data 360 Integration",icon:"🌐",desc:"Unifies and harmonizes Account Management data through the Life Sciences Data Kit with prebuilt data streams and mappings. Integrates activity plans, marketable products, presentations, provider visits, and sales territory data into Data 360 for comprehensive analytics.",tags:["DataStream","DataLakeObject"],docs:["Data 360 Integration unifies and harmonizes Life Sciences Cloud Account Management data through the Life Sciences Data Kit, which provides prebuilt data mappings, data streams, and data model objects. When deployed, the Data Kit automatically creates data streams for key Life Sciences objects including activity plans, marketable products, presentations, provider visits, and sales territory data, enabling comprehensive analytics through Data 360 and Tableau Next visualizations.","The integration transforms complex life sciences data into actionable insights by consolidating information from across the Customer Engagement platform into Data 360's unified data model. Data Lake Objects (DLOs) and Data Model Objects (DMOs) standardize the data format, while prebuilt data streams handle the continuous flow of data from Salesforce objects into the analytics layer. This approach eliminates the need for custom ETL processes and ensures consistent data representation across analytics tools.","Smart content search is a key capability enabled through Data 360 integration. By creating vector search indexes of presentation content, the system enables semantic search across presentation files, going beyond simple name and metadata matching. Data 360 processes raw presentation file text, extracts meaning, and chunks content into semantically meaningful units before generating vector embeddings for search. This feature requires both the Life Sciences Cloud and Data 360 licenses.","The Data 360 integration supports the broader analytics ecosystem including Tableau Einstein dashboards for patient support programs and operational efficiency metrics. Organizations can extend the prebuilt data streams and mappings with custom configurations to include additional objects and fields relevant to their specific analytics requirements, leveraging the harmonized data foundation for cross-functional reporting and insights."],connections:[{"planet":"intelligent_content","desc":"Unified data powers content and engagement analytics"},{"planet":"site_mgmt","desc":"Harmonized data supports site and investigator analysis"}]},
    {id:"trigger-handlers",name:"Trigger Handler Administration",icon:"⚡",desc:"Centralized console for managing all Life Sciences Customer Engagement trigger handlers. Admins can view, activate, and deactivate trigger handlers across dozens of objects to control automated business logic for samples, visits, territories, and workflows.",tags:["LifeScienceTriggerHandler"],docs:["Trigger Handler Administration provides a centralized console in the Life Sciences Customer Engagement Admin Console for viewing, activating, and deactivating all trigger handlers across the platform. The console covers trigger handlers for dozens of objects spanning Account, AccountPlan, ActivityPlan, AppAlertTerritory, AssessmentTask, Consent, Healthcare Provider, Inventory, Product, Visit, and many more, giving administrators complete visibility and control over automated business logic.","Trigger handlers automate critical business processes across the platform. For sample management, handlers like CalculateShippedQuantityHandler, SampleLimitTransactionHandler, and ProductDisbursementInventoryOpCreation manage sample limit calculations and disbursement processing. For account management, HealthcareProviderAffiliationHandler creates primary affiliations, while ContactPointEmail, Phone, and Social handlers maintain accurate provider contact information. Visit-related handlers enforce record locking, manage visitor sharing, and control survey invitation access.","Each trigger handler has a defined trigger condition specifying when it fires: beforeInsert, afterInsert, beforeUpdate, afterUpdate, beforeDelete, afterDelete, or afterUndelete. Administrators can search for specific handlers using the Object API Name dropdown or search field, and toggle individual handlers on or off. Some handlers serve as alternatives to batch jobs, providing real-time processing capabilities versus the batch approach for large-scale operations.","Proper trigger handler configuration is a prerequisite for many Life Sciences Cloud features. Sample Management requires activating over 15 handlers before creating sample records. Consent Management, Key Account Management, Medical Insights, Remote Engagement, and Workflow Management each have their own required handler activations. The console helps administrators track which handlers are active and troubleshoot issues by enabling or disabling specific automation logic without code changes."],connections:[{"planet":"sample_mgmt","desc":"Trigger handlers automate sample limit calculations"}]},
  ],
  dataFlow:["Admin configures trigger handlers, workflows, and license validation rules","Provider data syncs from IQVIA OneKey via MuleSoft Direct integration","App Alerts deliver targeted notifications to territory-assigned sales reps","Multi-object components and tree views present consolidated data on record pages","Data 360 integration harmonizes activity and engagement data for analytics"],
  connections:[{"planet":"account_mgmt","desc":"Common components enhance account and provider management"},{"planet":"engagement_execution","desc":"Workflows and alerts support visit execution"},{"planet":"intelligent_content","desc":"Data integration powers content and analytics"},{"planet":"sample_mgmt","desc":"License validation and triggers support sample compliance"},{"planet":"site_mgmt","desc":"Shared data infrastructure supports site management"},{"planet":"platform_extensions","desc":"OmniStudio FlexCards and Data Mappers power extensible UI"}]
},

participant_mgmt: {
  packages: ["core"],
  name: "Participant Management",
  icon: "🧪",
  color: "#7C3AED",
  description: "Streamlines the process of recruiting and enrolling participants in clinical trials by orchestrating each stage from initial recruitment through enrollment. Participant Management uses a FHIR R4 and USCDI-aligned data model to store interoperable clinical trial data. The system provides criteria-based search for trial discovery, Einstein Candidate Matching for automated participant-trial matching, OmniStudio-powered prescreening flows, consent management with digital verification, and randomization capabilities for controlled clinical studies. Clinical trial coordinators monitor recruitment and enrollment progress through the Clinical Excellence Console.",
  components: [
    {id:"recruitment",name:"Participant Recruitment",icon:"🔍",desc:"Digitizes candidate recruitment with criteria-based search for trial discovery, OmniStudio components for prescreening, and Einstein Candidate Matching to automatically match candidates to clinical trials based on eligibility criteria.",tags:["ResearchStudyCandidate","ResearchStudy","CareProgram","EnrollmentEligibilityCriteria"],docs:["Participant Recruitment in Life Sciences Cloud digitizes and optimizes candidate recruitment for clinical trials, addressing common challenges such as delays in identifying suitable candidates, high recruitment costs, and inefficient registration processes. The platform enables users to effortlessly locate suitable trials through Criteria-Based Search and Filter, quickly assess candidate eligibility through OmniStudio-powered prescreening flows, streamline registration with automated processes, and automatically match candidates to clinical trials using Einstein Candidate Matching.","The recruitment workflow centers on the Research Study Searchable Field, a consolidated object populated by the Data Processing Engine that joins data from multiple objects including Care Programs, Care Program Details, Care Program Sites, and Locations. Candidates can search for trials through an Experience Cloud site using configurable search criteria including distance filtering with Google Maps geolocation, field-based filtering (Intent, Phase, Research Study Type, Eligible Gender, Status), and range-type filtering for numeric and date fields.","OmniStudio components power the prescreening and registration processes. The TrialManagement_CandidateEligibilityAndRegistrationMerged OmniScript handles both eligibility assessment and candidate registration in a single flow. Integration Procedures evaluate candidate responses against expression sets to determine eligibility matches. The system supports reCAPTCHA for security, duplicate management rules to prevent duplicate account creation, and the ability to save assessment responses linked to specific candidates.","The recruitment experience supports multiple user types through five permission sets: Clinical Trial Manager, Clinical Trial Coordinator, Clinical Trial Participant, Clinical Trial Guest, and Clinical Trial Site Coordinator in Experience Cloud. The system uses a FHIR R4 and USCDI-aligned data model for interoperability, and supports both guest and authenticated user access through Experience Cloud sites with configurable sharing rules and object-level permissions."],connections:[{"planet":"account_mgmt","desc":"Candidate accounts link to patient records"},{"planet":"site_mgmt","desc":"Recruitment targets sites identified through site management"}]},
    {id:"enrollment",name:"Participant Enrollment",icon:"📝",desc:"Manages the enrollment journey from consent to randomization using Salesforce orchestration capabilities. Includes consent management with authorization forms, digital verification, and configurable enrollment workflows with status tracking.",tags:["CareProgramEnrollee","AuthorizationFormConsent","AuthorizationForm","InfoAuthorizationRequest"],docs:["Participant Enrollment manages the complete journey from consent to randomization using Salesforce orchestration capabilities. After candidates pass recruitment screening, they become participants and proceed through enrollment stages including consent form preparation, digital signing, and optional randomization into comparison groups. The enrollment process uses flows and invocable actions to digitize both consent management and randomization, creating a configurable participant enrollment journey.","The enrollment data model uses Care Program Enrollee records to represent participants enrolled in care programs, with Authorization Form Consent records tracking how and when each participant consented. Care Program Enrollee Status Period records capture historical changes to enrollment stages, while Info Authorization Request records track individual consent requests and their completion status. This model supports full audit trail requirements for clinical trial compliance.","Enrollment workflows can be orchestrated using Salesforce Flow orchestrations that combine consent and randomization steps into a unified journey. The system supports custom sharing rules for both guest and authenticated users on Experience Cloud sites, enabling clinical trial participants to view and sign consent forms through a self-service portal. Duplicate management rules prevent redundant account and lead creation during the registration-to-enrollment transition.","The enrollment features require the Participant Enrollment Add-On license and integrate with Care Programs for ongoing participant management and with Advanced Therapy Management for assigning enrolled participants to therapy procedures. Clinical trial coordinators monitor enrollment progress through the Clinical Excellence Console, tracking metrics such as conversion rates, candidate status across enrollment stages, and rejection ratios."],connections:[{"planet":"care_programs","desc":"Enrolled participants join care programs for ongoing management"},{"planet":"advanced_therapy","desc":"Enrolled participants can be assigned to advanced therapy procedures"}]},
    {id:"consent-management",name:"Consent Management",icon:"📄",desc:"Digitizes the preparation, distribution, and tracking of consent forms with versioned authorization form texts, multi-language support, and digital verification. Tracks data use purposes and links consent records to specific research studies.",tags:["AuthorizationFormText","AuthorizationFormDataUse","DataUsePurpose","DigitalVerification"],docs:["Consent Management for Participant Management digitizes the preparation, distribution, and tracking of consent forms for clinical trials with versioned authorization form texts, multi-language support, and digital verification. The system uses Authorization Form records to define specific consent form versions with effective dates, Authorization Form Text records to store form content and language settings, and Data Use Purpose records to specify the reasons for contacting or collecting data from participants.","The consent workflow is powered by Salesforce Flows that can be cloned and customized. The Review and Create Consent Requests flow handles the core consent logic, while screen flows enable users to prepare consent forms by selecting data use purposes and specifying whether to use digital verification credentials or scribble pad signatures. A separate screen flow enables participants to view, access, and digitally sign consent forms, acknowledging their informed consent for clinical trials.","Custom Sharing must be enabled in Participant Management Settings to allow users with Customer Community Plus licenses to share Authorization Form Texts and Data Use Purpose records with Accounts, Contracts, and Users specified in Information Authorization Request records. Digital Verification settings support configurable credentials for electronic signatures, and the system integrates with Data Protection and Privacy settings for access to the Authorization Form Consent object.","The consent management system maintains a complete audit trail of all consent activities including form versions, signing timestamps, verification methods, and data use purposes. This ensures organizations can demonstrate compliance with regulatory requirements governing informed consent in clinical trials, including the ability to track exactly which version of a consent form each participant signed and under what data use authorization."],connections:[{"planet":"care_programs","desc":"Consent forms govern participation in care programs"}]},
    {id:"randomization",name:"Randomization",icon:"🎲",desc:"Supports randomized clinical trials by configuring randomization algorithms, blocks, and slots for research studies. Enables stratified randomization with criteria-based grouping and comparison groups to assign participants to treatment or control arms.",tags:["ResearchStudyRandomization","ResearchStudyRandomizationBlock","ResearchStudyRandomizationBlockSlot","ResearchStudyComparisonGroup"],docs:["Randomization in Participant Management supports randomized clinical trials by configuring algorithms, blocks, and slots to assign participants to treatment or control comparison groups. The system uses Research Study Randomization records to define the algorithm configuration, Research Study Randomization Block records for block-level parameters, Research Study Randomization Block Slots for individual assignments linked to comparison groups, and Research Study Comparison Group records with configurable allocation ratios.","Block randomization creates structured blocks where each block contains a predetermined number of slots linked to specific comparison groups. The allocation ratio field on Research Study Comparison Group records controls the distribution of participants across groups. For example, with three groups and ratios of 1:1:2 in a 100-participant study, the system distributes 25, 25, and 50 participants respectively. Block generation can be configured during the research study randomization setup phase.","The randomization feature supports multiple implementation approaches: block algorithm type with central randomization level, criteria-based block randomization using flows and invocable actions for stratified randomization with criteria-based grouping, and custom algorithm types for organizations with specialized randomization requirements. The randomization API is available as an invocable action, enabling use through Salesforce Flows or REST API invocations.","To enable randomization, administrators turn on Research Study Randomization in Participant Management Settings and create a Decision Table. Randomization criteria records enable stratified randomization by defining criteria for grouping participants. The feature integrates with the enrollment workflow through Salesforce orchestration capabilities, allowing consent and randomization to be combined into a unified enrollment journey for participants."],connections:[{"planet":"site_mgmt","desc":"Randomization aligned with site-specific study protocols"}]},
    {id:"candidate-matching",name:"Einstein Candidate Matching",icon:"🤖",desc:"Uses generative AI to automatically evaluate candidates against research study inclusion and exclusion criteria. Produces detailed evaluation results with matched criteria status, reasoning, and reference records for clinical trial coordinator review.",tags:["CareProgramEnrollmentEvaluationResult","DiagnosticSummary"],docs:["Einstein Candidate Matching is an AI-enabled feature that automatically evaluates candidates against the inclusion and exclusion criteria of research studies, enabling clinical trial coordinators and recruiters to build targeted candidate cohorts efficiently. The feature uses generative AI to understand a research study's eligibility criteria and searches through structured and unstructured data including electronic medical records (EMR) and electronic health records (EHR) to identify qualifying candidates.","The system offers two implementation approaches: Einstein Generative AI capabilities for intelligent, context-aware matching that understands complex criteria, and a Data Processing Engine with Actionable Lists approach for basic criteria-based filtering without AI. The AI implementation uses the preconfigured Evaluate Research Study Candidate prompt template, triggered by the Candidate Evaluation for Research Study flow, along with the Get Candidate Matching Context Data custom invocable action to retrieve candidate medical data.","Candidate matching can be initiated from multiple entry points through built-in quick actions: Evaluate Candidate on Account and Research Study Candidate detail pages, and Evaluate Candidates on Account and Research Study Candidate list view pages and Actionable Lists. The system produces Care Program Enrollment Evaluation Result records with detailed outcomes showing matched criteria status, reasoning, and reference records for each candidate-criterion pair, enabling informed decision-making by trial coordinators.","The feature requires the FHIR-aligned Clinical Data Model to be enabled along with Einstein Generative AI capabilities and Context Definition settings. A batch job processes large volumes of candidate records within the evaluation flow, and administrators can troubleshoot execution errors through the Monitor Workflow Services setup page. The Candidate Matching feature integrates with the clinical data model objects including Allergy Intolerance, Care Observation, Diagnostic Summary, Health Condition, and Medication Request for comprehensive candidate evaluation."],connections:[{"planet":"account_mgmt","desc":"Candidate matching evaluates patient account clinical data"}]},
    {id:"clinical-excellence-console",name:"Clinical Excellence Console",icon:"📊",desc:"Purpose-built console app for clinical trial coordinators to track and monitor participant recruitment and enrollment progress. Displays enrollment dashboards with conversion rates, candidate status, rejection ratios, and quick links to key features.",tags:["ResearchStudyCandidateStatusPeriod","CareProgramStatusPeriod"],docs:["The Clinical Excellence Console is a purpose-built app for clinical trial coordinators and recruiters to track and monitor participant recruitment and enrollment progress from a single interface. The app consolidates disparate tracking tools into three main sections: a Home page with enrollment dashboards, a Research Study Candidates view with patient cards and evaluation results, and a Research Studies view for managing trial details and building candidate cohorts.","The Home page features an enrollment dashboard displaying key performance indicators including the total number of active research studies, average candidate conversion rate across studies, candidate status counts across different enrollment stages, a Candidate Enrollment Progress bar graph comparing current and target enrollee counts, and a Candidate Rejection Ratio bar graph showing rejection percentages per study. These metrics are powered by installable reports that can be customized with org-specific status values and formula fields.","The Research Study Candidates section provides access to individual candidate records featuring patient cards that display medical information from FHIR-aligned clinical data model objects. Coordinators can add new Medication Requests, Health Conditions, Allergies, and Immunization records directly from the patient card. The Evaluation Results tab shows detailed outcomes of Einstein Candidate Matching, including inclusion criteria matches, exclusion criteria flags, match status, reasoning, and links to matching reference records.","The console is built using OmniStudio FlexCards for the enrollment dashboard visualization, displaying research study counts, conversion rate percentages, and candidate enrollment status. Setting up the console requires installing reports, configuring OmniStudio settings (enabling Metadata, disabling Managed Package Runtime), and updating the Included Care Program Status Values on dashboard components to align with the organization's defined values."],connections:[{"planet":"site_mgmt","desc":"Console tracks site-level enrollment metrics"}]},
  ],
  dataFlow:["Clinical trial manager creates research study with inclusion and exclusion criteria","Einstein Candidate Matching evaluates candidates against eligibility criteria","Qualified candidates complete prescreening via OmniStudio-powered flows","Consent forms are prepared, sent, and digitally signed by participants","Randomization assigns participants to comparison groups","Clinical Excellence Console monitors enrollment progress and conversion rates"],
  connections:[{"planet":"account_mgmt","desc":"Participant accounts store patient and provider data"},{"planet":"site_mgmt","desc":"Sites host clinical trials for participant enrollment"},{"planet":"care_programs","desc":"Enrolled participants managed through care programs"},{"planet":"advanced_therapy","desc":"Participants may receive advanced therapy treatments"}]
},

site_mgmt: {
  packages: ["core"],
  name: "Site Management",
  icon: "🏥",
  color: "#D946EF",
  description: "Enables life sciences organizations to identify, evaluate, and select suitable clinical trial sites and investigators. Study managers use enhanced search capabilities to find sites and investigators, assess feasibility through configurable assessments with generative AI support, and assign weighted scores based on attributes like research experience and publications. The system includes Agentforce-powered site selection assistance, contract lifecycle management for clinical trial agreements, and stage management for tracking research study progress from initiation to closure.",
  components: [
    {id:"site-search",name:"Site and Investigator Search",icon:"🔍",desc:"Criteria-based search powered by Data Processing Engine to find clinical trial sites and investigators. Users can search across consolidated data from multiple objects, filter by attributes, and view AI-generated summaries of site and investigator profiles.",tags:["CareSiteInvestigatorSearchableField","ResearchStudySearchableField"],docs:["Site and Investigator Search enables study managers to find suitable clinical trial sites and investigators using criteria-based search powered by the Data Processing Engine. The engine joins, calculates, and transforms data from multiple objects including Healthcare Facility, Healthcare Provider, Care Specialty, Healthcare Practitioner Facility, and Accreditation into a consolidated Care Site Investigator Searchable Field object, providing a unified searchable dataset for site identification.","The search is configured through Criteria-Based Search and Filter with a default search configuration specific to the search definitions. Study managers can search across consolidated data, filter by attributes such as specialties and research experience, and view AI-generated summaries of site and investigator profiles directly from the search results page. The summarization feature presents critical information in a concise format using Einstein context definitions and prompt templates.","Setting up the search requires enabling Data Pipelines, configuring the Populate Care Site Investigator Searchable Field Data Processing Engine definition, and creating searchable object and search configurations. The searchable object configuration maps search criteria fields to specific fields in source objects, enabling suggested options as users type keywords. For Agentforce integration, search and filter is automatically configured when the Site Selection Assistance topic is set up.","The search integrates with the broader Site Management workflow, feeding results into feasibility assessment, scoring, and interest tagging processes. Study managers can perform searches from the Site Selection Console app or from pages where the Criteria-Based Search and Filter component is integrated. The Data Processing Engine definition must be run whenever data in source objects is updated to keep the searchable field current."],connections:[{"planet":"common_components","desc":"Search uses criteria-based search and filter framework"},{"planet":"participant_mgmt","desc":"Search results feed into participant recruitment planning"}]},
    {id:"site-assessments",name:"Site Feasibility Assessments",icon:"📋",desc:"Configurable questionnaires built on Discovery Framework for evaluating site suitability. Supports generative AI-assisted question creation from uploaded documents, prefill of repeated questions, formula-based scoring, and an assessment dashboard with histogram visualization.",tags:["AssessmentEnvelope","AssessmentEnvelopeItem"],docs:["Site Feasibility Assessments are configurable questionnaires built on the Discovery Framework that evaluate the suitability of clinical trial sites and their investigators. Study managers can create assessments manually or with the assistance of generative AI, which drafts assessment questions from uploaded PDF documents containing study-specific criteria. The system supports prefill of repeated questions from past assessments, saving investigators time when responding to similar questionnaires across multiple studies.","Assessments are distributed to site investigators through Experience Cloud portals, where investigators log in to respond to the questionnaire. Study managers can then review responses on an assessment dashboard that includes histogram visualization of results. The SiteManagementAssessmentDataVisualization FlexCard, added to the Research Study page, provides study managers with a visual overview of assessment details and site readiness across all participating sites.","The Discovery Framework supports formula-based scoring within assessments, enabling study managers to assign score values to each option in the questionnaire. This built-in scoring capability integrates with the broader site scoring system to create a comprehensive evaluation of site suitability. Assessment Envelope and Assessment Envelope Item objects store the assessment structure and individual responses, maintaining a complete record of the feasibility evaluation process.","The assessment workflow integrates with Site Management's guided setup, where administrators configure site feasibility scoring under the Configure Site Feasibility Score section. Generative AI assessment creation requires the Generative AI Assessment Questions permission set and supports uploading study protocol documents from which Einstein extracts and suggests relevant assessment questions, significantly accelerating the feasibility questionnaire creation process."],connections:[{"planet":"participant_mgmt","desc":"Assessment results inform participant recruitment site selection"}]},
    {id:"site-scoring",name:"Site and Investigator Scoring",icon:"🎯",desc:"Assigns weighted scores to sites and investigators based on attributes including research experience, trial performance, publications, and legal compliance. Scoring can leverage Business Rule Engine, Data 360 Calculated Insights, or proprietary external tools.",tags:["ScoreCategory","PartyPublication","Accreditation"],docs:["Site and Investigator Scoring enables study managers to classify and rank clinical trial sites and investigators by assigning weighted scores based on multiple attributes. These attributes include total years of research study experience, clinical trial performance metrics, cycle times, publication history, professional accreditations, and legal compliance status. Scores provide a quantitative basis for comparing potential sites and making data-driven selection decisions.","The scoring system supports three approaches for generating scores: the Business Rule Engine (BRE) for configurable rule-based scoring, Data 360 features like Calculated Insights or Einstein Studio for analytics-driven scoring, and integration of proprietary scores generated by external tools. This flexibility allows organizations to implement scoring methodologies that match their established site evaluation processes while leveraging Salesforce platform capabilities.","Score Category objects store the categorized scores for sites and investigators, while Party Publication and Accreditation objects capture the research publications and professional credentials that feed into scoring calculations. Assessment response scores from the Discovery Framework can also contribute to the overall site score, combining feasibility questionnaire results with attribute-based scoring for a comprehensive evaluation.","Scoring is configured through the Site Management guided setup under the Set Up Site Investigator Scoring section. Study managers can view and compare scores across sites through the Site Selection Console app, using the quantitative data alongside qualitative assessments and interest tags to make informed site selection decisions for their clinical trials."],connections:[{"planet":"common_components","desc":"Scoring uses shared analytics and business rules infrastructure"}]},
    {id:"site-selection-console",name:"Site Selection Console",icon:"🖥",desc:"Purpose-built console app that streamlines clinical trial site selection and activation. Provides study managers with centralized access to search results, assessment dashboards, site scoring, interest tags, and reports for efficient site identification.",tags:["ResearchStudy","CareProgram","CareProgramSite"],docs:["The Site Selection Console is a purpose-built app that streamlines clinical trial site selection and activation by consolidating key metrics, search results, assessment dashboards, scoring data, interest tags, and reports into a single interface. It eliminates the need for study managers to navigate between disconnected tools by providing centralized access to all features required for identifying, evaluating, and selecting clinical trial sites.","By default, the console includes items for Research Studies, Care Programs, Care Program Sites, Site and Investigator Search, and Care Site Investigator Searchable Fields. Study managers can add additional items to the default list or customize the available features. The console provides a comprehensive workflow from initial site discovery through feasibility assessment to final site activation, supporting the complete site selection lifecycle.","From the console, study managers can perform site and investigator searches using the Criteria-Based Search and Filter component, view AI-generated summaries of sites and investigators, generate and monitor feasibility assessments, review assessment dashboards with scoring visualizations, and manage interest tags for future reference. The console integrates with Agentforce for AI-assisted site identification and feasibility study recommendations.","Study managers and clinical trial coordinators can create and update study details using a single flow without updating object records separately through the console. The consolidated view enables efficient comparison of multiple sites across different evaluation criteria, supporting faster and more informed site selection decisions that accelerate the study startup process."],connections:[{"planet":"advanced_therapy","desc":"Selected sites host advanced therapy procedures"}]},
    {id:"stage-management",name:"Stage Management",icon:"📈",desc:"Defines and monitors the progression of research study or care program stages from initiation to closure. Establishes milestones, tracks operational progress at each stage, and provides a comprehensive view of stage progression on record pages.",tags:["CareProgramDetail","ResearchStudyProtocolInformation"],docs:["Stage Management simplifies the implementation of complex stages in a research study or care program by defining stage sequences, establishing milestones, and monitoring operational progress from initiation to closure. The feature provides a comprehensive view of a record's stage progression seamlessly on a record page, enabling study managers and clinical trial coordinators to track where each study or program stands in its lifecycle.","The system uses Care Program Detail records to define the detail records related to each stage, and Research Study Protocol Information records to capture protocol document details that govern the study progression. Stages can represent key phases such as study initiation, site identification, participant recruitment, enrollment, active treatment, data analysis, and study closure, with configurable milestones at each stage.","Stage Management integrates with the broader Site Management workflow by tracking enrollment milestones and study progression at both the overall study level and individual site level. This enables study managers to identify bottlenecks in the trial process, monitor compliance with protocol timelines, and take corrective action when stages fall behind schedule.","The feature is configured through the Site Management guided setup and works in conjunction with Contracts for Site Management to align contract milestones with study stage progression. Stage data feeds into the Site Selection Console for comprehensive study status monitoring, and supports the overall research study orchestration from initial planning through final closure and reporting."],connections:[{"planet":"participant_mgmt","desc":"Stage progression tracks enrollment milestones"}]},
    {id:"site-contracts",name:"Contracts for Site Management",icon:"📝",desc:"Manages the lifecycle of clinical trial contracts and agreements using Salesforce Contract Lifecycle Management. Supports non-disclosure agreements before feasibility, clinical trial agreements after site selection, and accelerates study startup through automated review and execution workflows.",tags:["CareProgramSiteContract","Contract"],docs:["Contracts for Site Management leverages Salesforce Contract Lifecycle Management (CLM) to manage the entire lifecycle of clinical trial contracts and agreements from authoring to activation. The system supports two primary contract types in the clinical trial workflow: non-disclosure or confidentiality disclosure agreements executed before site feasibility assessments, and clinical trial agreements established after site selection and qualification.","Care Program Site Contract records represent the association between a care program site and its contracts, linking the contractual agreements to specific clinical trial locations. This data model enables study managers to track which sites have completed their contractual requirements, identify sites awaiting agreement execution, and monitor the overall contract status across all sites participating in a study.","The contract workflow accelerates the study startup and site activation process by automating review and execution workflows. Sponsors and clinical trial organizations can generate agreements securely, route them through approval processes, and execute them digitally, significantly reducing the time between site selection and site activation. This streamlined process helps organizations meet aggressive trial timelines and regulatory requirements.","Contracts for Site Management integrates with Agentforce for AI-assisted site selection and contract workflow optimization. The feature works alongside Stage Management to align contract execution milestones with overall study stage progression, ensuring that sites complete their contractual requirements before advancing to active participation in the clinical trial."],connections:[{"planet":"agentforce","desc":"Agentforce assists with site selection and contract workflows"}]},
    {id:"interest-tags",name:"Interest Tags",icon:"🏷",desc:"Categorizes sites and investigators with up to three levels of hierarchical tags for future identification and organization. Study managers use tags to mark sites for specific research study types and quickly locate previously evaluated locations.",tags:["InterestTag"],docs:["Interest Tags enable study managers to categorize and organize clinical trial sites and investigators using a hierarchical tagging system with up to three levels of categories. Tags provide a flexible classification mechanism for marking sites and investigators for specific research study types, therapeutic areas, or operational characteristics, enabling quick identification and retrieval of previously evaluated locations for future studies.","The tagging system works with Healthcare Facility and Healthcare Provider objects, requiring Topics to be enabled for these objects before interest tags can be used. Tags are created and managed through the Site Management guided setup, and the Interest Tags component is added to the Research Study page to enable study managers to view and manage tags in context with their study records.","Study managers use interest tags to build a knowledge base of site capabilities and investigator expertise over time. When planning new studies, they can quickly filter and identify sites that have been previously tagged with relevant specialties, experience levels, or facility capabilities, reducing the time needed for site identification in subsequent trials. This institutional knowledge persists across studies and study managers.","Interest tags integrate with the Site Selection Console and the Criteria-Based Search and Filter infrastructure, allowing tags to be used as additional filter criteria when searching for sites and investigators. The hierarchical organization with up to three levels supports structured taxonomies such as Therapeutic Area > Indication > Subspecialty, enabling precise categorization that scales with the organization's growing clinical trial portfolio."],connections:[{"planet":"common_components","desc":"Tags integrate with search and filter infrastructure"}]},
  ],
  dataFlow:["Study manager creates research study with protocol information and eligibility criteria","Data Processing Engine consolidates site and investigator data into searchable objects","Criteria-based search finds matching sites and investigators with AI summaries","Feasibility assessments are sent to site investigators via Experience Cloud portal","Assessment responses are scored and visualized on the assessment dashboard","Selected sites proceed through contract workflows and stage management to activation"],
  connections:[{"planet":"participant_mgmt","desc":"Selected sites recruit and enroll clinical trial participants"},{"planet":"common_components","desc":"Shared search, workflow, and data infrastructure"},{"planet":"agentforce","desc":"Agentforce assists with site selection and feasibility"},{"planet":"advanced_therapy","desc":"Sites host advanced therapy treatment procedures"}]
},

advanced_therapy: {
  packages: ["core"],
  name: "Advanced Therapy Management",
  icon: "🧬",
  color: "#F43F5E",
  description: "Supports the orchestration of complex cell and gene therapies involving multiple sequential steps performed across different sites. Advanced Therapy Management provides Multi-Step Scheduling for booking appointment slots across service territories in a single flow, therapy orchestration using Salesforce Flows for automated stage and task execution, and Chain of Custody and Chain of Identity tracking to maintain pharmaceutical regulatory compliance. The system coordinates the full therapy lifecycle from patient intake through apheresis, manufacturing, and infusion, with configurable work procedures, service territory relationships, and shift-based capacity management.",
  components: [
    {id:"multi-step-scheduling",name:"Multi-Step Scheduling",icon:"📅",desc:"Enables booking appointment slots for all steps of a therapy procedure at once across multiple service territories. Uses service territory relationships, shift-based availability, and optimized slot formation logic to find and present the most suitable appointment chains.",tags:["ServiceAppointment","ServiceAppointmentGroup","WorkProcedure","WorkProcedureStep"],docs:["Multi-Step Scheduling enables booking appointment slots for all steps of a therapy procedure at once across multiple service territories. The feature brings together data about different sites, resources, and appointment slots into two tabs: Schedule Appointments and Reschedule Appointments. Users can conduct basic and advanced searches to view available time slots for all work types configured per their duration requirements, then book preferred slots for the entire therapy chain in a single workflow.","The scheduling system uses service territory relationships to streamline searches by providing information about affiliated territories where consecutive work types are performed. For example, if apheresis is performed at one center, the system uses service territory relationships to automatically identify which manufacturing and infusion centers are affiliated, presenting slot availability across the entire therapy chain. Advanced search supports up to 5 work types with 3 locations each for finding optimal appointment chains.","Slot availability is determined through a combination of shifts and time slots. Shifts are created for specific work types at service territories and can define different availability windows for different procedures, but are limited to approximately 3 months. Time slots are defined for service territories as a whole and can span longer periods but apply uniformly to all work types. The scheduling policy configures which method to use, and the system's internal optimization starts slot formation from the work type with the fewest available slots to minimize permutations.","Multi-Step Scheduling supports full and partial rescheduling. Full rescheduling creates a new service appointment group starting from the first work type. Partial rescheduling starts from any work type except the first, canceling downstream appointments and rebooking them in the existing group while respecting lead time requirements. The Appointment Slots Lightning component on Care Program Enrollee pages provides Book, Reschedule, and Cancel buttons with visibility controlled by a customizable Salesforce Flow based on appointment group status."],connections:[{"planet":"site_mgmt","desc":"Scheduling uses sites configured as service territories"},{"planet":"participant_mgmt","desc":"Appointments are booked for enrolled care program participants"}]},
    {id:"therapy-orchestration",name:"Therapy Orchestration",icon:"⚙",desc:"Implements complex therapy workflows using Salesforce Flow orchestrations with customizable stage and substage subflows. Automatically generates runtime work order and task records, assigns tasks to care team members by role, and monitors therapy progress from intake to completion.",tags:["CareProgramEnrolleeWorkOrder","CareProgramEnrolleeWorkOrderStep","AssessmentTask"],docs:["Therapy Orchestration implements complex therapy workflows using Salesforce Flow orchestrations where a parent orchestration flow references a series of subflows that execute all components of a therapy. Each flow is highly flexible and can be customized to the specific needs of the organization. The orchestration automatically generates runtime records including Care Program Enrollee Work Orders for therapy stages, Care Program Enrollee Work Order Steps for substages, and Assessment Task records for individual therapy tasks.","The orchestration maps therapy constructs to Salesforce objects at setup and runtime levels. Work Procedures define the overall therapy (such as Cell and Gene Therapy), Work Types represent stages (such as Apheresis, Manufacturing, Infusion), Work Type Steps represent substages (such as Identity Verification), and Action Plan Templates with component tasks define individual activities. At runtime, these generate corresponding work order and work order step records with assessment tasks assigned to care team members by role.","A therapy workflow involves multiple stages that occur in sequence or in parallel, each with substages that must be completed in sequential order. For example, the apheresis stage includes substages like patient identity verification, biosample collection, and biosample delivery, each containing tasks assigned to different users that can execute in parallel. The Process Advanced Therapy Work Orders orchestration flow manages the progression between stages, moving to the next step only after the current stage and its custody requirements are complete.","Setting up Therapy Orchestration requires configuring a care program, a corresponding work procedure with the ATMOrchCnd orchestration flow reference, work procedure steps with sequence numbers and lead times, work types with operating hours, and action plan templates with task flows. Teams, team members, and participant roles are configured to control task assignment at every step of the therapy, and the orchestration supports both standard and customized flow implementations."],connections:[{"planet":"care_programs","desc":"Orchestration flows are linked to care program enrollees"},{"planet":"pharmacy_benefits","desc":"Therapy tasks may trigger pharmacy benefit verifications"}]},
    {id:"work-procedures",name:"Work Procedures and Types",icon:"📋",desc:"Defines therapy procedures as a hierarchy of work procedures, work types, and work type steps with configurable sequence, lead times, and duration. Work procedure steps represent stages like apheresis, manufacturing, and infusion with their ordering and timing requirements.",tags:["WorkProcedure","WorkType","WorkProcedureStep","WorkTypeStep","WorkTypeExtension"],docs:["Work Procedures and Types define therapy procedures as a hierarchy of configurable elements that model the complete structure of advanced therapies. A Work Procedure stores information about the overall process (such as Cell and Gene Therapy) and is linked to a Care Program through the Reference Record field. Work Types represent individual treatment steps (such as Apheresis, Manufacturing, Infusion) with configurable operating hours, estimated duration, and duration units.","Work Procedure Steps bring together Work Types and Work Procedures, storing sequence numbers that define the order of therapy steps and lead times that specify the minimum time required before each step can begin. The Lead Time Unit Type can be set at either the work procedure level (as a default) or overridden at the individual work procedure step level using Hours, Days, or Minutes. A maximum of 10 work types can be scheduled within a single work procedure.","Work Type Steps represent substages within each Work Type, modeling the detailed activities within a therapy stage. For example, the Apheresis work type might include Identity Verification, Biosample Collection, and Biosample Delivery as work type steps. Work Type Extensions add supplementary information to work types, including icon URLs for visual representation and flags for scheduling requirements and non-standard service territory relationships.","The hierarchical structure supports granular lead time management for transportation logistics by modeling transport as a separate work type with its own lead time and adding it as a work procedure step. When coordinators book appointment slots, they can schedule transportation logistic slots with varying pickup times. This data model provides the foundation for both Multi-Step Scheduling and Therapy Orchestration, ensuring consistent therapy configuration across scheduling and execution."],connections:[{"planet":"site_mgmt","desc":"Work types are performed at specific service territory sites"}]},
    {id:"service-territories",name:"Service Territory Management",icon:"🏥",desc:"Manages the locations and resources where therapy steps are performed. Configures parent-child service territory hierarchies, assigns service resources modeled as assets, establishes site-to-site relationships for consecutive work types, and controls slot availability through shifts and operating hours.",tags:["ServiceTerritory","ServiceTerritoryMember","ServiceTerritoryRelationship","ServiceTerritoryWorkType"],docs:["Service Territory Management configures the locations and resources where advanced therapy steps are performed, using a parent-child hierarchy of service territories. The parent service territory represents the overall organization where a work procedure takes place (such as a Cell and Gene Therapy Center), while child service territories represent specific locations where individual work procedure steps are performed (such as Apheresis Center, Manufacturing Center, Infusion Center).","Service Resources are modeled as assets and represent the medical staff, equipment, or facilities assigned to perform work at a service territory. Resources are linked to territories through Service Territory Member records, which establish the assignment of a service resource to a specific territory. Shift records define the availability windows for service territory members, and Shift Work Topic records further specify availability for particular work types, enabling different scheduling patterns for different procedures at the same location.","Service Territory Relationships establish site-to-site mappings between service territories based on the work types performed, enabling Multi-Step Scheduling to automatically identify affiliated locations for consecutive therapy steps. For example, a relationship between an Apheresis Center and a Manufacturing Center ensures that when users book apheresis appointments, the system knows to look for manufacturing slots at the affiliated center. These relationships streamline the search process and ensure therapeutic continuity.","Operating hours are configured for both service territories and work types, controlling when each location or procedure type is available. Service Territory Work Type records indicate whether slots are published (available for booking) for particular work procedure steps at specific territories. The combination of service territories, resources, shifts, operating hours, and territory relationships provides the complete infrastructure for managing multi-site therapy scheduling and execution."],connections:[{"planet":"site_mgmt","desc":"Service territories map to clinical trial sites"}]},
    {id:"chain-of-custody",name:"Chain of Custody and Identity",icon:"🔗",desc:"Maintains a digital trail of the patient's biosample as it passes through therapy stages, steps, and tasks for pharmaceutical regulatory compliance. Chain of Identity ensures the right patient receives the right treatment by assigning unique identifiers to collected biosamples.",tags:["CustodyChainEntry","CustodyItem"],docs:["Chain of Custody (CoC) and Chain of Identity (CoI) maintain pharmaceutical regulatory compliance throughout the advanced therapy lifecycle by tracking biosamples as they move through therapy stages, steps, and tasks. CoC creates a digital trail documenting every handoff and transformation of the patient's biosample from collection through processing to reinfusion. CoI ensures the right patient receives the right treatment by assigning and tracking unique identifiers for each collected biosample.","Custody records are created automatically through Therapy Orchestration workflows. When a Care Program Enrollee Work Order is in progress, the Override Custody Verification Type When Work Order Is Changed flow creates related custody records. Similarly, when a work order step is in progress, the corresponding step-level flow creates step-level custody records. The Custody Verification Type Override decision table determines the verification requirements based on work type, work procedure, service territory, work type step, and country.","Each custody entry can require electronic signatures, configured through Digital Verification Setup records (signature trails) and Digital Verification Details records (signature specifics). The Custody Verification Type Override record specifies the number of signatures required (or Not Applicable for steps that do not require signatures), links to the appropriate signature trail, and assigns priority to condition combinations. The Evaluate Step and Task Completion Status flow checks whether all custody requirements for each step and task have been fulfilled before the orchestration advances.","Chain of Identity is maintained by assigning a unique identifier to the custody item, which can originate from Salesforce or external systems. Custody Chain Entry objects track all custody-related changes including timestamps of events and new data generated after each change, providing a complete audit trail. This comprehensive tracking ensures organizations can demonstrate full chain of custody compliance during regulatory inspections and supports the safety standards required for personalized medicine therapies."],connections:[{"planet":"participant_mgmt","desc":"Custody chain tracks biosamples linked to enrolled participants"}]},
    {id:"appointment-management",name:"Appointment Management",icon:"📆",desc:"Provides the Appointment Slots Lightning component for viewing, booking, rescheduling, and canceling therapy appointments. Supports full and partial rescheduling with lead-time awareness, booking request confirmation flows, and conditional button visibility based on appointment group status.",tags:["ServiceAppointment","ServiceAppointmentGroup","Shift","ShiftWorkTopic"],docs:["Appointment Management provides the Appointment Slots Lightning component for viewing, booking, rescheduling, and canceling therapy appointments on Care Program Enrollee record pages. The component can also be configured on Account, Case, and Opportunity record pages. It displays scheduled and canceled appointments in a unified interface, with Book New Slots, Reschedule Slots, and Cancel Slots buttons whose visibility is controlled by the service appointment group status and a customizable Salesforce Flow.","The booking workflow involves two user roles: Qualified Treatment Center (QTC) coordinators who search for and book appointment slots creating booking requests, and Gene Therapy Coordinators (GTC) who review and confirm the requests. The Confirm Booking Request quick action, powered by a Salesforce Flow, enables GTC coordinators to approve requests directly from the Care Program Enrollee record page. Profile-based visibility controls determine which work procedure steps each user role can see.","Appointment management supports both full and partial rescheduling with lead-time awareness. Full rescheduling creates a new service appointment group and sets the original group to Rescheduled status. Partial rescheduling operates within the existing group, canceling downstream appointments from the selected work type and rebooking them while respecting lead time constraints. The system also allows disregarding lead time restrictions for the preceding work type in urgent cases, such as when a patient's condition becomes critical.","Service appointment groups track the overall status of appointment chains. The Book New Slots button appears only when no active appointment groups exist or when existing groups have Canceled or Rescheduled status, and the care program enrollee's status is Active. At any point, only one service appointment group can be active. The component integrates with the broader Advanced Therapy Management infrastructure including work procedures, service territories, shifts, and operating hours to present accurate slot availability."],connections:[{"planet":"care_programs","desc":"Appointment slots displayed on care program enrollee records"}]},
  ],
  dataFlow:["Admin configures work procedures with therapy stages, work types, and lead times","Service territories, resources, and shifts are set up for each treatment location","QTC coordinator searches and books appointment slots across all therapy steps","GTC coordinator reviews and confirms the booking request","Therapy orchestration flow executes stages, generates work orders, and assigns tasks","Chain of Custody tracks biosample movement through each therapy step to completion"],
  connections:[{"planet":"participant_mgmt","desc":"Advanced therapies treat enrolled clinical trial participants"},{"planet":"site_mgmt","desc":"Therapy procedures performed at qualified treatment sites"},{"planet":"care_programs","desc":"Therapies linked to care program enrollee records"},{"planet":"pharmacy_benefits","desc":"Therapy tasks may require pharmacy benefit verification"}]
},

care_programs: {
  packages: ["core"],
  name: "Care Programs & Financial Assistance",
  icon: "💜",
  color: "#EC4899",
  description: "Manages patient support programs from enrollment through benefit disbursement. Care Programs let organizations define structured activities such as therapy plans, wellness initiatives, financial assistance, and medication access programs. Enrollment flows guide reps through program selection, product and provider association, and consent capture via electronic signatures. Financial Assistance Programs automate eligibility determination using the Business Rules Engine, manage application and appeal workflows, and track benefit assignments and disbursements including copay coupons and reimbursement tracking.",
  components: [
    {id:"care-program-enrollment",name:"Care Program Enrollment",icon:"📋",desc:"Guides users through a streamlined enrollment process using Flow Builder. Reps select a program, add products and providers, capture participant consent, and create enrollee records with membership cards and enrollment dates.",tags:["CareProgram","CareProgramEnrollee","CareProgramEnrollmentCard"],docs:["Care Program Enrollment provides a streamlined, guided process for enrolling patients in structured programs such as therapy plans, wellness initiatives, financial assistance, and medication access programs. Using Flow Builder, administrators clone and configure the Program Enrollment flow to define how users select a program, add related products and providers, and capture participant consent. The enrollment flow creates Care Program Enrollee records with membership cards, enrollment dates, and opt-out tracking.","The enrollment process supports both in-person and remote consent capture. When participants are physically present, they can review consent forms and provide electronic signatures on a tablet or mobile device. Participants who are not physically present can log into an Experience Cloud site to view their care program card, review associated consent documents, and provide consent digitally. The system supports multiple enrollments in the same care program when configured by administrators.","Administrators configure user permissions and organization-wide sharing settings to control access to care program objects. Person account records serve as the recommended record type for care plan participants, combining account and contact fields into one record. The Care Program Enrollments API enables external system integration by mapping source system fields to Salesforce target entities and attributes, supporting automated enrollment from third-party platforms."],connections:[{"planet":"participant_mgmt","desc":"Enrollees are linked to patient accounts and contact records"},{"planet":"advanced_therapy","desc":"Advanced therapy programs use care program enrollment for patient onboarding"}]},
    {id:"care-program-products-providers",name:"Products & Providers",icon:"🏥",desc:"Associates medications, devices, and healthcare providers with care programs. Care program products define which treatments are offered, while care program providers link practitioners and facilities to specific program offerings.",tags:["CareProgramProduct","CareProgramProvider","CareProgramHealthcareProvider"],docs:["Care Program Products and Providers define the medications, devices, and healthcare practitioners associated with each care program. Care Program Product records link specific treatments to programs, while Care Program Provider records associate healthcare facilities and practitioners with program offerings. Administrators create these records from the App Launcher and associate them with the appropriate care program, specifying status and product details.","The Products and Providers component supports a hierarchical relationship model where each care program product references a standard Product record, and each care program provider references an Account record representing the provider organization. During enrollment, the Program Enrollment flow presents available products and associated providers for participant selection, ensuring patients are connected with the correct treatments and practitioners.","Care Program Healthcare Provider records create associations between healthcare professionals and care program providers, enabling care teams to identify the primary practitioner for each provider. This association allows teams to look up all healthcare practitioners involved with a specific care program provider, supporting coordinated care delivery across the program lifecycle."],connections:[{"planet":"pharmacy_benefits","desc":"Care program products include medications verified through pharmacy benefits"}]},
    {id:"consent-management",name:"Consent & Authorization",icon:"✍",desc:"Manages consent documents, authorization forms, and electronic signatures for care program enrollment. Supports multi-language consent text, document libraries, and Experience Cloud sites where participants can review and sign forms digitally.",tags:["AuthorizationForm","AuthorizationFormConsent","AuthorizationFormText","DataUsePurpose"],docs:["Consent and Authorization manages the consent documents, authorization forms, and electronic signatures required for care program enrollment. The system uses Data Use Purpose records as containers for consent forms associated with each care program, supporting multiple forms per program. Authorization Form records store document metadata including revision numbers, effective dates, and signature requirements, while Authorization Form Text records manage multi-language versions of consent content.","Administrators upload consent documents to file libraries with configurable folder-level accessibility. The system supports cloning existing consent documents from one Data Use Purpose record to another, enabling efficient reuse across programs. Authorization Form Data Use junction records connect consent forms to their associated care programs, establishing the relationship between documents and program requirements.","Experience Cloud integration allows program participants to log into their site, view their care program card, and provide consent for associated documents remotely. The system supports digital signature capture, and administrators can configure whether signature is required or if the form is informational only. Multi-language support ensures consent forms display in the correct locale by matching the Authorization Form Text locale field to the site or org language."],connections:[]},
    {id:"financial-assistance",name:"Financial Assistance Programs",icon:"💰",desc:"Streamlines enrollment of patients in assistance programs to manage out-of-pocket medical expenses. Uses the Business Rules Engine for eligibility determination, automates application and appeal workflows, and tracks benefit assignments and disbursements including copay coupons.",tags:["Applicant","ApplicationForm","BenefitAssignment","BenefitDisbursement","Program","ProgramEnrollment"],docs:["Financial Assistance Programs streamline the enrollment of patients in assistance programs that help manage out-of-pocket medical expenses. Patient service representatives identify suitable programs based on specific criteria, submit applications on behalf of enrollees, and track application status through approval or rejection. The system uses the Business Rules Engine to automate eligibility determination through configurable decision tables and expression sets that evaluate insurance type, benefits status, and other criteria.","The enrollment workflow includes multiple stages: application submission, eligibility evaluation, benefit assignment, and benefit disbursement. When applications are rejected, patient service reps can file appeals with configurable limits and timeouts. By default, appeals time out after 30 days without action. The system supports copay coupons, reimbursement tracking, and various benefit frequencies including monthly, quarterly, yearly, and on-demand disbursements.","Financial Assistance Programs use a FHIR-aligned data model with objects including Applicant, Application Form, Benefit Assignment, Benefit Disbursement, and Program Enrollment. Setup requires OmniStudio for assessments powered by the Discovery Framework, and administrators must configure lookup tables, expression sets, care limit types, sharing rules, and field-level security. The FinancialAssistanceProgramContainer FlexCard is added to the Care Program Enrollee record page to provide the user interface.","Data management involves creating interconnected records including person accounts, care programs, care program enrollees, products, medications, purchaser plans, member plans, and program recommendation rules. The system uses two key decision table templates: Financial Assistance Program Eligibility and Financial Assistance Program Recommendation, both of which must be activated after creation to enable automated eligibility and program matching."],connections:[{"planet":"platform_extensions","desc":"Financial assistance uses assessments and OmniStudio for eligibility flows"}]},
    {id:"care-program-goals",name:"Program Goals & Eligibility",icon:"🎯",desc:"Defines measurable goals for care programs such as health metric targets and treatment milestones. Eligibility rules control which participants qualify for specific programs based on configurable criteria, enabling automated enrollment screening.",tags:["CareProgramGoal","CareProgramEligibilityRule"],docs:["Program Goals and Eligibility enables organizations to define measurable objectives for care programs and control participant qualification through configurable criteria. Care Program Goals are associated with specific care programs and include attributes such as goal name, start date, end date, and status. Goals can represent health metric targets, treatment milestones, or behavioral objectives that guide program activities and measure outcomes.","Care Program Eligibility Rules define the inclusion criteria for participation in a care program, using the Care Program Eligibility Rules object to associate programs with enrollment eligibility criteria records. These rules enable automated screening during the enrollment process, evaluating whether participants meet the defined requirements before they can be enrolled. Administrators configure eligibility rules through the care program setup, supporting both simple criteria matching and complex rule combinations.","The goals and eligibility framework integrates with the broader care program lifecycle. Goals provide measurable benchmarks that care coordinators use to track participant progress, while eligibility rules serve as gatekeepers that ensure only qualified individuals enter specific programs. Together, these components support data-driven program management by establishing clear objectives and qualification standards."],connections:[]},
    {id:"device-registration",name:"Device Registration & Shipping",icon:"📦",desc:"Registers healthcare devices for patients and creates shipping requests to deliver monitoring equipment. Care coordinators track biometric data from registered devices, identify gaps in care metrics, and engage patients for follow-up interventions.",tags:["Asset","ShippingRequest"],docs:["Device Registration and Shipping helps patients stay on course with their care metric targets by enabling care coordinators to register healthcare devices and create shipping requests for monitoring equipment delivery. The feature uses a Flow Builder-based screen flow called Register Device and Create Shipping Request, which administrators can configure to display both registration and shipping tabs, or restrict to one function based on user needs.","Device registration creates Asset records linking devices to patient accounts, while shipping requests capture delivery information including quantity, destination, and device type. The flow is added to the patient's person account page as a quick action, allowing care coordinators to initiate registrations and shipments directly from the patient record. Products represent device types, and users select from available products during the registration or shipping process.","Care coordinators use registered device data to track biometric readings, identify gaps in care metrics, and engage patients for follow-up interventions. The feature supports both web and mobile workflows, and the organization-wide default sharing setting for the Product object must be set to Public Read/Write for device registrations to function correctly in newer Salesforce orgs."],connections:[{"planet":"participant_mgmt","desc":"Device registrations are tied to patient accounts for care tracking"}]},
    {id:"care-program-analytics",name:"Program Analytics",icon:"📊",desc:"Dashboards for patient engagement, adherence, and churn analysis. Tracks enrollment metrics, retention rates, assessment completion, and case resolution times across care programs. Payer and benefits dashboards monitor verification status and financial assistance coverage.",tags:["CareProgramEnrollee"],docs:["Patient Support Program Analytics provides Tableau Einstein dashboards that give program leads and patient services reps data-driven insights to optimize operational efficiency and improve patient outcomes. Integrated with Data 360, the dashboards deliver detailed visualizations and analysis of key performance indicators including patient enrollment status, program completion milestones, engagement levels, retention rates, and churn trends.","Program Lead Analytics dashboards offer consolidated views across multiple programs, tracking metrics such as total programs, total patients enrolled, patients assessed, enrollment rates, assessment outcomes, health outcome improvement, patient satisfaction, and quality of life indicators. The Payer and Benefits dashboard monitors total payers, patients needing financial assistance, benefit verification status, and payer efficiency analysis including lead payer identification and amount coverage analysis.","Patient Services Rep Analytics dashboards provide program-specific insights helping care agents track individual program KPIs. The Patient Engagement dashboard for reps includes patient adherence and churn analysis sections that identify at-risk patients, while the Case Status and Resolution Analysis section monitors open cases, average resolution times, case status distribution, and case aging. These dashboards filter by region, patient support program, and facility name for targeted analysis.","Setup requires configuring a Data 360 connection, installing data kit bundles, deploying data streams, and adding Tableau Next Dashboard components to app home pages. Administrators assign Data Cloud User, Clinical Trial Manager, and Tableau Next Admin permission sets, and must enable Discovery Framework, Surveys, Site Management, and Participant Management to support full data ingestion."],connections:[]},
  ],
  dataFlow:["Admin defines care program with products, providers, and consent documents","Rep enrolls patient using guided enrollment flow and captures consent","Eligibility rules evaluate patient qualification for financial assistance","Business Rules Engine determines benefit assignments and amounts","Benefits are disbursed and tracked through the program lifecycle"],
  connections:[{"planet":"participant_mgmt","desc":"Enrollees reference patient account records"},{"planet":"advanced_therapy","desc":"Advanced therapies use care program enrollment"},{"planet":"pharmacy_benefits","desc":"Pharmacy benefits verification supports care program medications"},{"planet":"platform_extensions","desc":"Assessments and OmniStudio power eligibility and enrollment flows"}]
},

pharmacy_benefits: {
  packages: ["core"],
  name: "Pharmacy Benefits",
  icon: "💊",
  color: "#FB7185",
  description: "Verifies patient pharmacy coverage and manages benefits through a FHIR-CARIN and NCPDP-aligned data model. Patient services reps use guided flows to initiate electronic or manual verification requests to clearinghouses and payers, receiving detailed coverage information including copay, coinsurance, and deductibles. Einstein generative AI accelerates the process by generating call scripts for missing coverage fields and producing concise benefit summaries. Periodic reverification ensures patients maintain continuous medication access without coverage gaps.",
  components: [
    {id:"verification-requests",name:"Verification Requests",icon:"📝",desc:"Enables reps to create electronic or manual verification requests for pharmacy benefits. Each request covers a single member plan and includes patient, practitioner, drug, and pharmacy information. Electronic requests integrate with clearinghouses via MuleSoft.",tags:["CareBenefitVerifyRequest","CoverageBenefit","CoverageBenefitItem"],docs:["Verification Requests enable patient services representatives to initiate electronic or manual verification of pharmacy benefits coverage. Each request covers a single member plan and includes information about the patient, practitioner, drug, and pharmacy. Representatives can generate multiple requests for different drugs under any member plan available for a patient, and can create new member plans directly from the care program enrollee record page.","Manual verification requests allow representatives to directly contact payors to obtain coverage details and manually enter the response into the benefits summary section. Electronic verification requests automate the process through MuleSoft integration with third-party clearing houses, using FHIR-CARIN and NCPDP-aligned APIs. The electronic request sends an RTPBC (Real-Time Pharmacy Benefit Check) request to the clearing house, which connects with payors and returns coverage details.","The verification request flow auto-populates prescriber, drug, and pharmacy fields with values from the last verification request to speed up creation. Request statuses progress through stages including Pending, Acknowledged, Verified, Completed, Error, Rejected, and Timed Out, with electronic requests automatically updating status based on clearing house responses. Representatives can also convert manual requests to electronic verification and retry failed requests."],connections:[{"planet":"care_programs","desc":"Verification requests are initiated from care program enrollee records"},{"planet":"agentforce","desc":"Agentforce automates benefits reverification workflows"}]},
    {id:"coverage-benefits",name:"Coverage Benefits & Limits",icon:"🛡",desc:"Stores detailed pharmacy coverage information including copay, coinsurance, deductibles, out-of-pocket maximums, and lifetime limits. Coverage benefit items represent specific services covered by insurance plans, with item limits tracking expenditure thresholds and eligibility.",tags:["CoverageBenefit","CoverageBenefitItem","CoverageBenefitItemLimit","CareLimitType"],docs:["Coverage Benefits and Limits stores the detailed pharmacy coverage information returned from verification responses. Coverage Benefit records represent the pharmacy benefits provided to a patient under a purchaser's plan, including coverage type and final coverage status code. Coverage Benefit Item records represent specific services covered by the insurance plan, tracking individual benefit categories.","Coverage Benefit Item Limit records track expenditure thresholds, coverage levels, eligibility, and exclusions for specific benefits. The system supports a comprehensive set of care limit types including CoPay, CoInsurance, Deductibles, DeductiblesApplied, DeductiblesMet, InfusionCoInsurance, InfusionCoPay, Lifetime Maximum (LTM), Out-of-Pocket Maximum (OopMax), OopMaxMet, OutOfPocketApplied, RemainingLTM, and Total coverage amounts.","History tracking on the Coverage Benefit Item Limit object enables representatives to view previous values and editors of each response field, supporting audit trails and change management. The Benefits Summary section on the verification request displays all coverage details including coverage status, copay amounts, and coinsurance, with the ability to edit individual fields or bulk-edit through the Edit Benefits action."],connections:[]},
    {id:"member-payer-plans",name:"Member & Payer Plans",icon:"📄",desc:"Manages insurance coverage details through member plans representing individual subscriber coverage and purchaser plans representing payer offerings. Tracks payer relationships, plan details, and coverage types to support accurate benefits verification across multiple insurance providers.",tags:["MemberPlan","PurchaserPlan"],docs:["Member and Payer Plans manages insurance coverage details through two complementary objects. Member Plan records represent the insurance coverage details for an individual member or subscriber, including plan information and coverage types. Purchaser Plan records represent the payer plan that a purchaser makes available to its members and their dependents, defining the offerings available from each insurance provider.","In pharmacy benefits verification, each verification request is created for a single member plan. Representatives can create member plans directly from the care program enrollee record page using the Add Member Plan action on the Pharmacy Benefits Verification tab, eliminating the need to navigate to the Member Plan object separately. When a patient has multiple member plans, representatives can consult with the patient to determine which plan to use for verification.","The data model supports tracking of payer relationships across multiple insurance providers. Payors are represented as business accounts with associated identifiers, contact point addresses, phone numbers, and email addresses. The system maintains referential integrity between member plans, purchaser plans, and the care program enrollee records that drive the verification workflow."],connections:[{"planet":"account_mgmt","desc":"Payer accounts and insurance organizations are managed as business accounts"}]},
    {id:"medication-management",name:"Medication & Code Sets",icon:"💉",desc:"Maintains medication records, prescription requests, and standardized code sets used in pharmacy benefits verification. Units of measure define medication quantities while code sets store coverage status codes aligned with industry standards for interoperable data exchange.",tags:["Medication","MedicationRequest","CodeSet","UnitOfMeasure"],docs:["Medication and Code Sets maintains the drug records, prescription requests, and standardized coding used throughout pharmacy benefits verification. Medication records store detailed information about prescribed drugs, while Medication Request records represent orders for medication supply including administration instructions. The Product object serves as the base representation for drugs prescribed to patients in care programs.","Code Sets define the metrics that explain patients' pharmacy benefits coverage status, such as Covered, Not Covered, or Covered with Restrictions. Administrators configure Code Set Type picklist values and create individual code set records that align with industry standards for interoperable data exchange. Code Set Bundle records group related codes together for organized management.","Units of Measure records define medication quantities used in verification requests. The system requires mg (milligrams), mL (milliliters), and Each as standard unit codes for electronic verification requests. Administrators configure the Type picklist on the Unit of Measure object to categorize units by Weight, Amount, or Volume, ensuring accurate medication quantity representation in verification requests and coverage responses."],connections:[{"planet":"advanced_therapy","desc":"Medication records support advanced therapy treatment protocols"}]},
    {id:"einstein-pharmacy",name:"Einstein for Pharmacy Benefits",icon:"🤖",desc:"Leverages Einstein generative AI to generate call scripts with missing coverage fields and produce concise benefit summaries. AI-powered flows accelerate verification by automating repetitive tasks and helping reps quickly gather information from payers.",tags:["CareBenefitVerifyRequest"],docs:["Einstein for Pharmacy Benefits leverages generative AI to accelerate the verification process through two key capabilities: call script generation and benefits summary generation. Both features use Einstein Embedded AI to trigger Salesforce flows that invoke Context Service for data hydration, map information into suitable formats using invocable actions, and pass structured data to prompt templates connected to large language models.","The Generate Call Script flow creates a structured script divided into four sections: patient information, insurance coverage information, prescribed drug details, and a list of missing coverage fields. Representatives use this script when calling payors to efficiently gather missing information from the benefits summary. The script is generated from the CallScriptForPharmacyBenefits context definition and the Summarize Call Script prompt template.","The Generate Benefits Summary flow produces a concise summary of a patient's pharmacy benefits that can be shared with patients, prescribers, and practitioners. The summary includes patient information, insurance coverage, drug details, pharmacy benefits, additional information, and recommended next steps. It uses the PharmacyBenefitsSummary context definition and the Summarize Patient Pharmacy Benefits prompt template. Both features default to the OpenAI GPT 4 Turbo model and can be customized through cloned prompt templates."],connections:[]},
    {id:"benefits-reverification",name:"Benefits Reverification",icon:"🔄",desc:"Periodically checks patient eligibility for pharmacy benefits to ensure continuous medication access. Orchestration flows manage the reverification lifecycle including patient outreach, response collection, electronic verification submission, and benefit summary distribution to healthcare professionals.",tags:["CareBenefitVerifyRequest"],docs:["Benefits Reverification periodically checks patient eligibility for pharmacy benefits to ensure continuous medication access without coverage gaps. Program leads initiate reverification using a screen flow that collects reverification parameters and generates new Care Benefit Verify Request records with Pending status. These records are then distributed to patient services reps through shared list views or direct assignment for processing.","The reverification automation operates through a multi-stage orchestration process. The first stage, Update Patient Personal and Healthcare Details, uses Agentforce to send emails with secure assessment URLs to patients, waits for responses, and updates patient details. The second stage, Process Electronic Verification Request, sends FHIR-compliant requests to clearing houses through MuleSoft and validates essential benefits in the response. If electronic verification is incomplete, the process falls back to manual verification.","The manual verification fallback stage sends assessment URLs to payors to confirm benefits details, waits for responses, validates essential benefits including Copay, Coinsurance, and Lifetime Maximum, and shares benefit summaries with healthcare professionals. Each orchestration stage includes timeout handling and error recovery mechanisms, with configurable timeframes set by administrators. The automation reduces manual work and accelerates the reverification cycle.","When issues such as network connectivity prevent reverification from completing, records show an Error status. Representatives can change the status from Error to Copy, which triggers the Copy Care Benefit Verify Request Fields flow to create required records and update prescription and coverage benefit fields automatically."],connections:[{"planet":"agentforce","desc":"Agentforce automates the reverification process with AI-powered email drafting and patient response summarization"}]},
  ],
  dataFlow:["Rep initiates verification request from care program enrollee record","Request is sent electronically to clearinghouse via MuleSoft or manually to payer","Clearinghouse returns coverage details including copay, coinsurance, and deductibles","Coverage benefits and limits are stored on the verification response","Einstein generates benefit summary for sharing with patient and healthcare provider"],
  connections:[{"planet":"care_programs","desc":"Pharmacy benefits serve care program enrollees"},{"planet":"advanced_therapy","desc":"Benefits verification supports therapy medication access"},{"planet":"agentforce","desc":"Agentforce accelerates reverification workflows"},{"planet":"account_mgmt","desc":"Payer and provider accounts support benefits processing"}]
},

medtech: {
  packages: ["core"],
  name: "MedTech Commercial",
  icon: "🩺",
  color: "#84CC16",
  description: "Supports medical device manufacturers with end-to-end commercial engagement from sales agreements through field inventory management. Sales agreements track planned versus actual quantities at the product level with schedule frequencies. Account-based forecasting creates baseline predictions using market and account growth factors. Intelligent Sales gives field reps mobile tools for surgical case visits, cycle counts, product transfers, and barcode scanning, with real-time visibility into shortfalls and revenue impact projections.",
  components: [
    {id:"sales-agreements",name:"Sales Agreements",icon:"📃",desc:"Creates account-level volume and price agreements with multiple products, planned quantities, prices, and discounts. Supports schedule frequencies including monthly, quarterly, and yearly. Enables comparison of planned versus actual quantities as orders are booked to monitor compliance.",tags:["SalesAgreement","SalesAgreementProduct"],docs:["Sales Agreements enable medical device manufacturers to create account-level volume and price agreements that track planned versus actual sales quantities at the product level. Each agreement can include multiple products with specified planned quantities, prices, and discounts. Agreements support schedule frequencies including One Time, Monthly, Quarterly, and Yearly to align with business objectives and contractual terms.","Over time, organizations compare planned quantities to actual quantities as orders are booked against the agreement, providing real-time compliance monitoring. The feature includes a configurable Path component that visualizes the status progression of agreements, helping users plan accordingly. Sales agreements are set up through the Manufacturing settings in Salesforce Setup and require the Manufacturing Sales Agreements permission set.","Sales agreements support bidirectional conversion with quotes through the Convert Record screen flow, which uses the SalesAgreementQuotesConversion context definition to map field relationships between records. Bell notifications keep users informed about conversion job status, and administrators can clone or extend the context definition to include additional custom field mappings."],connections:[{"planet":"account_mgmt","desc":"Sales agreements are created at the account level for customer organizations"}]},
    {id:"account-forecasting",name:"Account & Advanced Forecasting",icon:"📈",desc:"Creates account-level forecasts for multiple products using market and account growth factors relative to prior year actuals. Configurable forecast horizons and granularity support monthly or quarterly buckets. Reps and managers can edit, annotate, and track forecast changes with revenue impact metrics.",tags:["AccountForecast","ForecastingItem"],docs:["Account and Advanced Forecasting creates account-level forecasts for multiple products using market and account growth factors relative to prior year actuals. Administrators configure forecast horizons and bucket granularity, supporting monthly or quarterly forecast periods. The baseline forecast is generated automatically and can be adjusted by account reps and sales managers with the ability to edit values, annotate changes, and track forecast modifications.","Forecast changes are tracked with revenue impact metrics, giving managers visibility into how adjustments affect overall performance projections. The system supports configurable forecast views that allow users to drill into product-level and account-level detail, compare forecast periods, and identify trends. Advanced forecasting integrates with the broader MedTech Commercial engagement workflow from lead generation through order fulfillment.","The forecasting capability ensures transparency across sales and commercial units by providing a shared view of projected demand. Sales operations teams use forecasts to anticipate product needs, plan inventory allocation, and identify accounts requiring attention. The feature is part of the Commercial Excellence capabilities available to Life Sciences Cloud users with Health Cloud Starter or Health Cloud Foundation permission sets."],connections:[{"planet":"account_mgmt","desc":"Forecasts are tied to customer accounts and product portfolios"}]},
    {id:"account-manager-targets",name:"Account Manager Targets",icon:"🎯",desc:"Converts business growth plans into measurable revenue, quantity, and other targets distributed across team members. Targets can be allocated by products and accounts with monthly, quarterly, or yearly distribution for periodic reviews. Values can be updated and redistributed at any time.",tags:["AccountManagerTarget"],docs:["Account Manager Targets converts business growth plans into measurable revenue, quantity, and other target types that are distributed across team members. Organizations create targets with specific measure types and allocate percentage-based distributions to individual team members, ensuring accountability for meeting market demands and organizational requirements.","Targets can be strategically distributed by products and accounts, with temporal distribution options including monthly, quarterly, or yearly periods for periodic reviews and progress tracking. Target values can be updated and redistributed at any time, providing flexibility to adapt to changing market conditions and business priorities without requiring new target creation.","The feature supports multiple measure types beyond revenue and quantity, enabling organizations to define custom performance indicators aligned with their strategic objectives. Account Manager Targets integrate with the sales agreement and forecasting workflows, providing a goal-setting framework that connects high-level business plans to individual contributor performance measurement."],connections:[]},
    {id:"surgical-case-visits",name:"Surgical Case Visits",icon:"🏥",desc:"Schedules and manages surgical case visits where reps fulfill product orders at provider locations. Action plan templates define visit tasks including patient registration and order authorization. Visibility into product shortfalls with estimated revenue impact enables proactive transfer requests.",tags:["Visit","Visitor","VisitedParty","ActionPlanTemplate","AssessmentTask","ProductRequired"],docs:["Surgical Case Visits enable sales operations teams and field reps to schedule and manage visits where reps fulfill product orders at healthcare provider locations. Action Plan Templates define the required visit tasks, including Patient Registration and Order Authorization flows that automatically create account records and order records during visit completion. Visits are created using the Work Type object with the Is Used For Inventory Projection checkbox enabled.","The Intelligent Sales platform provides visibility into product shortfalls for upcoming surgical case visits, with estimated revenue impact figures to support proactive decision-making. When shortfalls are detected, either the rep or their sales operations contact can arrange product transfers from nearby inventories. The visit lifecycle includes scheduling, task execution on the mobile app, and completion with required task validation.","Sales operations teams schedule visits from the desktop application, assigning reps, products, and assessment tasks. Sales reps execute visits using the Salesforce mobile app, completing required tasks before ending the visit. The system supports both primary and secondary visitors, with only primary visitors able to initiate and end visit tasks. Visited Party records track the contacts that reps visit at account locations."],connections:[{"planet":"sample_mgmt","desc":"Visit inventory draws from field sample and product inventories"},{"planet":"engagement_execution","desc":"Visit execution supports commercial engagement workflows"}]},
    {id:"cycle-counts",name:"Cycle Count Management",icon:"📋",desc:"Schedules planned and ad hoc inventory audits at field locations. The mobile app supports barcode scanning for serialized products and automatic quantity tallying. Blind cycle counts hide expected quantities from reps for unbiased counting. Key performance indicators track expected versus counted quantities.",tags:["Visit","GenericVisitTask","GenericVisitKeyPerformanceIndicator","WorkType"],docs:["Cycle Count Management schedules planned and ad hoc inventory audits at field locations to verify that recorded quantities match physical inventory. Planned cycle counts are scheduled at regular intervals by sales operations teams using the desktop application, while sales reps can schedule ad hoc counts from the mobile app when high-value visits require inventory verification. Cycle count visits use Work Type records with the Cycle Counting checkbox enabled.","The mobile app supports barcode scanning for serialized products, automatically adding scanned serial numbers to a tally list and counting quantities. For non-serialized products, reps manually enter counted quantities. Blind cycle counts hide expected quantities from reps by enabling the Blind Cycle Counting checkbox on the Work Type, ensuring unbiased counting for audit accuracy.","Key Performance Indicator records track expected versus counted quantities for each product at each location. Generic Visit Task and Generic Visit Task Context records serve as definition templates that the system uses to create instance records for specific cycle count visits. Assessment Indicator Definitions specify the data type for quantities, which must always be Number for cycle counts. After completion, results are stored in KPI records associated with the cycle count visit."],connections:[]},
    {id:"field-inventory",name:"Field Inventory & Transfers",icon:"📦",desc:"Manages product inventories across field locations with real-time availability projections tied to upcoming visits. When shortfalls are detected, reps or sales ops can request product transfers from nearby inventories. Serialized product tracking associates individual serial numbers with inventory locations.",tags:["ProductItem","ProductFulfillmentLocation","ProductTransfer","ProductRequest","SerializedProduct","ProductAvailabilityProjection"],docs:["Field Inventory and Transfers manages product inventories across field locations with real-time availability projections tied to upcoming visits. Product Item records track the combination of a product, its inventory location, and available quantity. Product Fulfillment Location records tie sales reps to specific inventories, accounts, and account locations, establishing the ownership and responsibility relationships for field stock.","When product shortfalls are detected for upcoming surgical case visits, reps or sales operations can request product transfers from nearby inventories. Product Transfer records capture the transfer details, while Product Request and Product Request Line Item records manage the request workflow. The system automatically creates these records through the request transfer flow, streamlining the logistics of moving inventory between locations.","Serialized Product records associate individual serial numbers with Product Item records, with each new serialized product automatically incrementing the Product Item quantity by one. Product Availability Projection records provide real-time projections of product availability based on upcoming visits and pending transfers. Access to visits and inventories is controlled through Sharing Settings, profile-based permissions, and custom Apex triggers that ensure users see only their assigned visits and inventories."],connections:[{"planet":"product_mgmt","desc":"Product records from the catalog feed into field inventory tracking"}]},
    {id:"record-conversion",name:"Quote & Agreement Conversion",icon:"🔄",desc:"Automates bidirectional conversion between quotes and sales agreements using a screen flow. Context definitions map field relationships between records, prefilling values during conversion. Bell notifications keep users informed about conversion job status.",tags:["SalesAgreement","Quote"],docs:["Quote and Agreement Conversion automates bidirectional conversion between quotes and sales agreements using a screen flow. The Convert Record flow uses the SalesAgreementQuotesConversion context definition to map field relationships between source and target records, automatically prefilling values during the conversion process. Users can launch the flow from Convert to Sales Agreement or Convert to Quote quick actions on respective record pages.","Context definitions ensure efficient data mapping at every step of the conversion. Administrators can clone or extend the default SalesAgreementQuotesConversion context definition to include additional custom field mappings. The cloned context definition must be activated and referenced in the Convert Record flow before use. Users review and update prefilled values before completing the conversion.","Bell notifications keep users informed about the status of their record conversion jobs. The feature requires enabling both Sales Agreements and Quotes in the org, along with the Context Service Runtime and Manufacturing Sales Agreements permission sets. Record conversion is also available in orgs with Revenue Lifecycle Management and Health Cloud, provided that decision tables, pricing procedures, and product catalog management are properly configured."],connections:[]},
  ],
  dataFlow:["Sales ops creates sales agreements with planned product quantities and prices","Account-level forecasts are generated using growth factors and prior year actuals","Surgical case visits are scheduled and assigned to field reps with action plans","Reps execute visits on mobile app, completing tasks and fulfilling orders","Cycle counts verify field inventory accuracy with barcode scanning and quantity tracking"],
  connections:[{"planet":"product_mgmt","desc":"Medical device products feed into sales agreements and inventory"},{"planet":"sample_mgmt","desc":"Field inventory management intersects with sample tracking"},{"planet":"engagement_execution","desc":"Surgical visits support commercial engagement processes"},{"planet":"account_mgmt","desc":"Agreements and forecasts are tied to customer accounts"}]
},

agentforce: {
  packages: ["addon"],
  name: "Agentforce",
  icon: "🤖",
  color: "#65A30D",
  description: "Brings autonomous AI agents to Life Sciences Cloud for accelerating complex multi-step workflows. The Pharmacy Benefits Reverification agent automates patient outreach, data collection, verification request submission, and benefit summary distribution. The Site Selection Assistance agent streamlines clinical trial site identification by searching for sites and investigators, summarizing results, adding sites to research studies, and sending feasibility assessments. Both agents use prebuilt flows, prompt templates, and Einstein generative AI to reduce manual intervention across patient support and clinical operations.",
  components: [
    {id:"pharmacy-reverification-agent",name:"Pharmacy Reverification Agent",icon:"💊",desc:"Automates the benefits reverification process by drafting and sending patient emails with secure assessment links, summarizing patient responses, and updating verification request records. Uses Einstein generative AI flows to compare existing and updated patient details.",tags:["CareBenefitVerifyRequest"],docs:["The Pharmacy Reverification Agent automates the benefits reverification process by drafting and sending patient emails with secure assessment links, summarizing patient responses, and updating verification request records. The agent uses the Benefits Reverification topic with two primary actions: Draft or Revise Email, which creates an email containing an assessment URL for patients to verify their personal, drug, pharmacy, healthcare provider, and insurance details; and Summarize Patient Response, which analyzes the patient's assessment response and compares existing and updated information.","When no changes are detected in the patient's insurance details, an Update Details follow-up action becomes available that automatically updates the benefits verification request and associated records with the latest patient information. The agent integrates with prebuilt flows including Get Details for Benefits Reverification Email, Summarize Patient Response, Update Patient's Personal and Healthcare Details, and Upsert Context Service Data to execute the underlying automation steps."],connections:[{"planet":"pharmacy_benefits","desc":"Automates reverification workflows for pharmacy benefits requests"},{"planet":"account_mgmt","desc":"Accesses patient and payer account data during reverification"}]},
    {id:"site-selection-agent",name:"Site Selection Assistance Agent",icon:"🔍",desc:"Accelerates clinical trial site selection by searching sites and investigators using criteria-based filters, summarizing site and investigator profiles, adding sites to research studies, and sending feasibility assessments in bulk through Experience Cloud portals.",tags:["CareProgramSite","ResearchStudy"],docs:["The Site Selection Assistance Agent accelerates clinical trial site selection by helping study managers search for sites and investigators using criteria-based filters, summarize search results, add sites to research studies, and send feasibility assessments in bulk through Experience Cloud portals. The agent topic includes eight standard actions: Get Site Search Filters for Research Study, Add Sites Search Results to Study, Add Site and Investigator to Study, Summarize Site, Summarize Investigator, Send Site Feasibility Assessments, Go to Care Program Sites, and Get Omniscript IDs From Research Study.","Study managers use the agent to perform site selection operations without manually updating multiple objects or navigating through multiple pages. The agent creates Care Program Site records from search results, generates AI-powered summaries of site and investigator profiles, and orchestrates the distribution of feasibility questionnaires. Setup is configured through the Site Management guided setup, which ensures all required settings and prompt templates are correctly aligned."],connections:[{"planet":"site_mgmt","desc":"Extends site management with AI-powered search and summarization"},{"planet":"engagement_execution","desc":"Site feasibility assessments support clinical engagement workflows"}]},
    {id:"agent-topics-actions",name:"Agent Topics & Actions",icon:"⚙",desc:"Configurable topics and agent actions that define the scope and capabilities of each Agentforce agent. Topics group related actions like email drafting, response summarization, and record updates. Actions map to prebuilt flows and prompt templates that execute the underlying automation.",tags:["AgentTopic","AgentAction"],docs:["Agent Topics and Actions define the scope and capabilities of each Agentforce agent through configurable groupings of related agent actions. Topics serve as the organizing framework that determines which actions an agent can perform, while actions map to prebuilt flows and prompt templates that execute the underlying automation. Each topic includes a description and a set of agent actions with example utterances and use cases that guide the natural language interface.","The Benefits Reverification topic groups email drafting, response summarization, and record update actions for pharmacy benefits workflows. The Site Selection Assistance topic bundles eight actions covering site search, investigator lookup, study assignment, summarization, and feasibility assessment distribution. Actions are configured as Agent Quick Actions on specific objects such as Care Benefit Verify Request, enabling context-aware automation that responds to record-level utterances from users."],connections:[]},
    {id:"agent-flows-orchestration",name:"Agent Flows & Orchestration",icon:"🔄",desc:"Prebuilt flows that power Agentforce automation including verification status updates, email sending, patient detail updates, and assessment distribution. Orchestration stages manage multi-step processes with timeout handling, error recovery, and fallback to manual verification when automated steps fail.",tags:["Flow","OrchestratorRun"],docs:["Agent Flows and Orchestration provides the prebuilt flows that power Agentforce automation across Life Sciences Cloud. For Pharmacy Benefits Reverification, flows include Update Verification Request Status to Received Confirmation, Get Details for Benefits Reverification Email, Summarize Patient Response, Update Patient's Personal and Healthcare Details, and Upsert Context Service Data. For Site Management, prebuilt flows automate the AddSitesToStudy process and other site selection tasks.","Orchestration manages multi-step reverification processes through three stages: Update Patient Personal and Healthcare Details (sending emails, waiting for responses, updating records), Process Electronic Verification Request (initiating electronic verification, validating essential benefits, sharing summaries), and Process Manual Verification Request (sending payor emails, awaiting responses, validating benefits). Each stage includes timeout handling, error recovery, and fallback mechanisms that route to manual verification when automated steps fail."],connections:[]},
  ],
  dataFlow:["Agent receives task from rep or automated trigger","Topic and actions determine the workflow scope","Prebuilt flows execute tasks like email drafting and data summarization","Einstein generative AI processes patient responses or site information","Results are written back to Salesforce records and notifications sent to users"],
  connections:[{"planet":"pharmacy_benefits","desc":"Automates pharmacy benefits reverification"},{"planet":"site_mgmt","desc":"AI-powered site selection for clinical trials"},{"planet":"account_mgmt","desc":"Accesses account and patient data"},{"planet":"engagement_execution","desc":"Supports engagement workflows with autonomous agents"}]
},

platform_extensions: {
  packages: ["core"],
  name: "Platform Extensions",
  icon: "🧩",
  color: "#6366F1",
  description: "Extends Life Sciences Cloud with cross-cutting platform capabilities that enhance multiple product areas. The Advanced Patient Card uses OmniStudio FlexCards to display rich patient information from multiple objects. Assessments and surveys powered by Discovery Framework gather structured health data using industry-standard screeners. Electronic signatures provide 21 CFR Part 11-ready digital verification with signature trails. Intelligent Document Automation manages patient forms from intake through HIPAA-compliant processing. Product Catalog Management enables creation and classification of medical devices and pharmaceutical products with dynamic attributes.",
  components: [
    {id:"advanced-patient-card",name:"Advanced Patient Card",icon:"👤",desc:"Uses OmniStudio FlexCards to display comprehensive patient information from multiple objects on account record pages. Supports up to three records per object and retrieves data through OmniStudio Data Mappers, providing a flexible and customizable patient overview.",tags:["Account","FlexCard"],docs:["The Advanced Patient Card uses OmniStudio FlexCards to display comprehensive patient information from multiple objects on account record pages. The card retrieves data from standard and custom objects through OmniStudio Data Mappers, as long as the object has a reference to the Account object. It can display up to three records for each object, providing a flexible and customizable patient overview that consolidates information from across the data model.","To deploy the Advanced Patient Card, administrators add the HealthCloudPtCardPatientCard FlexCard component to the Account Lightning Record Page. Before configuration, the Managed Package Runtime setting in OmniStudio Settings must be disabled. The Advanced Patient Card and the standard Patient Card are two separate entities, and using the Advanced Patient Card has no impact on the standard Patient Card functionality."],connections:[{"planet":"account_mgmt","desc":"Patient cards display on account record pages"},{"planet":"common_components","desc":"Uses OmniStudio FlexCards and Data Mappers"}]},
    {id:"assessments-surveys",name:"Assessments & Surveys",icon:"📝",desc:"Gathers structured health information using industry-standard screeners and member feedback surveys powered by the Discovery Framework. Supports generative AI question generation, prefilled assessment questions, and external user assessments through Experience Cloud portals.",tags:["Assessment","AssessmentQuestion","AssessmentQuestionResponse","AssessmentIndicatorDefinition"],docs:["Assessments and Surveys gathers structured health information using industry-standard screeners and member feedback surveys powered by the Discovery Framework. The framework supports creating assessment questions, managing question versions, and collecting responses through configurable assessment flows. Generative AI capabilities enable automatic question generation, and assessments can be prefilled with previously submitted responses for streamlined follow-up evaluations.","Assessments support external user participation through Experience Cloud portals, where patients and members can complete screeners and surveys without logging into the main Salesforce org. The Discovery Framework must be enabled in Setup along with Enhanced Questions, Import or Export, and Sample Templates. Financial Assistance Programs and Pharmacy Benefits Reverification both use assessments for data collection, with deployable sample templates available through the Discovery Framework Sample Templates page.","The assessment data model includes Assessment, Assessment Question, Assessment Question Response, Assessment Question Version, and Assessment Indicator Definition objects. Omni Process Assessment Question Version junction records connect OmniScript processes with assessment question versions, enabling integration between OmniStudio flows and the Discovery Framework. Administrators deploy assessment templates, activate integration procedures, and configure OmniScript settings to enable assessment functionality."],connections:[{"planet":"care_programs","desc":"Assessments evaluate patient eligibility and care program outcomes"}]},
    {id:"electronic-signatures",name:"Electronic Signatures",icon:"✍",desc:"Provides 21 CFR Part 11-ready electronic signature functionality using Digital Verifications. Signature trails support sequential or parallel signing with designated verifiers. Users authenticate with CRM credentials and can sign on any device, with full audit trails for compliance.",tags:["DigitalVerificationSetup","DigitalVerificationSetupDetail","DigitalVerification"],docs:["Electronic Signatures provides 21 CFR Part 11-ready digital verification functionality using the Digital Verifications feature. Signature trails define the number of required signatures and whether designated verifiers must sign in a specific order (sequential) or in any order (parallel). Each signature trail is associated with a reference object and configured with a verification type specifying the required number of signatures and a record action type indicating when the trail is triggered.","Users authenticate with their CRM credentials to sign electronic records, and can sign on the same device as other signers or different devices. The Pending Signature component, added to Home pages or record detail pages, displays electronic signature records that are ready for signing or that are rejected but still open. Each record includes the signature request date, a link to the related reference record, and fields for signing action, comments, and location.","Setup requires creating connected apps, authentication providers, and named credentials for CRM credential validation. Decision tables store digital verification setup information, and administrators create flows to automatically generate digital verification records when reference records are created or updated. Electronic signatures are used for managing Chain of Custody in Advanced Therapy Management, verifying consent documents, and signing non-disclosure agreements and other critical records."],connections:[{"planet":"care_programs","desc":"Electronic signatures verify consent and chain of custody records"}]},
    {id:"document-automation",name:"Intelligent Document Automation",icon:"📄",desc:"Manages patient and member forms from intake through processing in a HIPAA-compliant digital workspace. Patients upload documents via Experience Cloud, forms are automatically routed to the right queue, and Intelligent Document Reader uses OCR with Amazon Textract to extract and map data to Salesforce fields.",tags:["DocumentChecklistItem","ContentDocument"],docs:["Intelligent Document Automation simplifies the document management process by managing patient and member forms from intake through processing in a HIPAA-compliant digital workspace. Patients can upload their own documents through an Experience Cloud site, and forms are automatically routed to the appropriate queue for faster review and processing. The feature reduces manual data entry and accelerates the delivery of care and services.","Intelligent Document Reader extends the automation with optical character recognition powered by Amazon Textract through an AWS account integration. Administrators specify the document type associated with each document, upload it, and map extracted fields to Salesforce object fields. The extracted information can create or update record fields or verify data already in the org, supporting automated data extraction from insurance cards, prescription forms, and other healthcare documents."],connections:[{"planet":"intelligent_content","desc":"Document automation integrates with content management for form processing"}]},
    {id:"product-catalog-mgmt",name:"Product Catalog Management",icon:"📦",desc:"Enables creation and management of medical devices, drugs, and drug samples through Revenue Cloud's Product Catalog Management. Supports product classifications with dynamic attributes, bundle definitions, qualification rules, and multiple selling models including one-time and term-defined.",tags:["Product2","ProductCatalog","ProductCategory","ProductClassification","ProductAttribute"],docs:["Product Catalog Management enables Life Sciences Cloud users to create and manage medical devices, drugs, and drug samples through Revenue Cloud's Product Catalog Management app. MedTech organizations use the app for products such as pacemakers, X-ray machines, and syringes, while Pharma organizations use it for drug classification and sample management. The app is available as part of the base Life Sciences Cloud license through the App Launcher.","The catalog supports comprehensive product organization through catalogs with Sales and Service types, hierarchical categories with subcategories and category trees, and product classifications with dynamic attribute templates. Product classification templates enable consistency across similar products by defining reusable attribute collections that products inherit, with the ability to override inherited attributes at the product level without impacting the template.","Products can be defined as simple, configurable bundles, or nonconfigurable bundles with cardinality relationships. Selling models include One Time, Term-Defined, and Evergreen options. The system supports product attributes with configurable categories, data types, picklist assignments, and visibility settings. Qualification rules and qualification rule procedures control product eligibility in the selling process. The data model includes Product Classification, Product Configuration Rule, Product Specification Type, and Attribute Category objects."],connections:[{"planet":"account_mgmt","desc":"Products are associated with accounts through orders and agreements"}]},
    {id:"enhanced-timeline",name:"Enhanced Timeline & Life Events",icon:"📅",desc:"Shows key events relating to patients or resources in chronological order on a single component. Life Events capture significant patient milestones that may impact healthcare, with custom event types, configurable icons, and contextual actions for follow-up.",tags:["PersonLifeEvent","TimelineItem"],docs:["Enhanced Timeline displays key events relating to patients or resources in chronological order on a single component, providing users with information from a single source of truth. The timeline shows data from objects as a sequence of events over time, with administrators choosing the base object and related objects to determine what information appears. Both standard and custom objects can be used as data sources.","Life Events capture significant milestones in a patient's life that may impact their healthcare, using the Person Life Event object. Administrators can create custom life event types, activate or deactivate them, and make them unique. Sensitive life event types can be hidden from certain users, default icons can be customized, and contextual actions can be configured for follow-up activities. The Life Events setup is configured through a guided setup page in Salesforce Setup, where administrators add the Life Events or Business Milestone component to record pages such as the patient's person account page."],connections:[{"planet":"care_programs","desc":"Life events and milestones track care program participant journeys"}]},
  ],
  dataFlow:["Patient data is gathered through assessments and document uploads","Advanced Patient Card displays consolidated patient information","Electronic signatures verify key records and consent documents","Document automation routes and processes forms with OCR extraction","Product catalog manages medical device and pharmaceutical offerings"],
  connections:[{"planet":"care_programs","desc":"Assessments and signatures support care program workflows"},{"planet":"account_mgmt","desc":"Patient cards and product catalog extend account capabilities"},{"planet":"common_components","desc":"OmniStudio FlexCards and Data Mappers power extensible UI"},{"planet":"intelligent_content","desc":"Document automation integrates with content management"}]
},

};
